import type { HandbookDocumentContent } from "../types";

const document: HandbookDocumentContent = {
  navHtml: "<div class=\"nav-brand\">ENGINEERING · PLATFORM TOOLS</div>\n  <div class=\"nav-title\">운영 도구 · Docker Linux vi nginx</div>\n  <a href=\"#bundle-index\"><span class=\"code\">INDEX</span>통합 문서</a>\n  <a href=\"#doc-deploy\"><span class=\"code\">DOC</span>Docker와 배포</a>\n  <a href=\"#doc-linux\"><span class=\"code\">DOC</span>리눅스</a>\n  <a href=\"#doc-vi\"><span class=\"code\">DOC</span>vi</a>\n  <a href=\"#doc-docker\"><span class=\"code\">DOC</span>Docker 예시</a>\n  <a href=\"#doc-nginx\"><span class=\"code\">DOC</span>nginx 예시</a>\n  <a href=\"#doc-deploy\"><span class=\"code\">SRC</span>Docker와 배포</a>\n<a href=\"#deploy-ch1\"><span class=\"code\">OPS-01</span>컨테이너란</a>\n  <a href=\"#deploy-ch2\"><span class=\"code\">OPS-02</span>이미지와 레이어</a>\n  <a href=\"#deploy-ch3\"><span class=\"code\">OPS-03</span>Dockerfile 기초·베스트 프랙티스</a>\n  <a href=\"#deploy-ch4\"><span class=\"code\">OPS-04</span>멀티스테이지·이미지 최적화</a>\n  <a href=\"#deploy-ch5\"><span class=\"code\">OPS-05</span>컨테이너 실행과 구성</a>\n  <a href=\"#deploy-ch6\"><span class=\"code\">OPS-06</span>레지스트리와 태깅</a>\n  <a href=\"#deploy-ch7\"><span class=\"code\">OPS-07</span>12-factor 앱</a>\n  <a href=\"#deploy-ch8\"><span class=\"code\">OPS-08</span>CI/CD 파이프라인</a>\n  <a href=\"#deploy-ch9\"><span class=\"code\">OPS-09</span>배포 전략</a>\n  <a href=\"#deploy-ch10\"><span class=\"code\">OPS-10</span>오케스트레이션 개요</a>\n  <a href=\"#deploy-ch11\"><span class=\"code\">OPS-11</span>용어집</a>\n  <a href=\"#deploy-ch12\"><span class=\"code\">OPS-12</span>운영 가능한 배포 심화</a>\n  <a href=\"#doc-linux\"><span class=\"code\">SRC</span>리눅스</a>\n<a href=\"#linux-ch1\"><span class=\"code\">LX-01</span>셸의 사고 모델</a>\n  <a href=\"#linux-ch2\"><span class=\"code\">LX-02</span>탐색·이동</a>\n  <a href=\"#linux-ch3\"><span class=\"code\">LX-03</span>파일 보기·편집</a>\n  <a href=\"#linux-ch4\"><span class=\"code\">LX-04</span>검색 — 텍스트와 파일</a>\n  <a href=\"#linux-ch5\"><span class=\"code\">LX-05</span>파일 조작</a>\n  <a href=\"#linux-ch6\"><span class=\"code\">LX-06</span>권한·소유권</a>\n  <a href=\"#linux-ch7\"><span class=\"code\">LX-07</span>프로세스·잡</a>\n  <a href=\"#linux-ch8\"><span class=\"code\">LX-08</span>파이프·텍스트 가공</a>\n  <a href=\"#linux-ch9\"><span class=\"code\">LX-09</span>네트워크·HTTP</a>\n  <a href=\"#linux-ch10\"><span class=\"code\">LX-10</span>디스크·시스템</a>\n  <a href=\"#linux-ch11\"><span class=\"code\">LX-11</span>압축·아카이브</a>\n  <a href=\"#linux-ch12\"><span class=\"code\">LX-12</span>원격·동기화</a>\n  <a href=\"#linux-ch13\"><span class=\"code\">LX-13</span>셸 환경·생산성</a>\n  <a href=\"#linux-ch14\"><span class=\"code\">LX-14</span>치트시트</a>\n  <a href=\"#doc-vi\"><span class=\"code\">SRC</span>vi</a>\n<a href=\"#vi-ch1\"><span class=\"code\">VI-01</span>사고 모델 — 모드와 문법</a>\n  <a href=\"#vi-ch2\"><span class=\"code\">VI-02</span>모드와 전환</a>\n  <a href=\"#vi-ch3\"><span class=\"code\">VI-03</span>이동 (모션)</a>\n  <a href=\"#vi-ch4\"><span class=\"code\">VI-04</span>편집 — 연산자</a>\n  <a href=\"#vi-ch5\"><span class=\"code\">VI-05</span>텍스트 객체</a>\n  <a href=\"#vi-ch6\"><span class=\"code\">VI-06</span>검색·치환</a>\n  <a href=\"#vi-ch7\"><span class=\"code\">VI-07</span>비주얼 모드</a>\n  <a href=\"#vi-ch8\"><span class=\"code\">VI-08</span>파일·창·저장·종료</a>\n  <a href=\"#vi-ch9\"><span class=\"code\">VI-09</span>생산성 + 치트시트</a>\n  <a href=\"#doc-docker\"><span class=\"code\">SRC</span>Docker 예시</a>\n<a href=\"#docker-ch1\"><span class=\"code\">DOCKER-01</span>Spring Boot Dockerfile</a>\n  <a href=\"#docker-ch2\"><span class=\"code\">DOCKER-02</span>.dockerignore·이미지 최적화</a>\n  <a href=\"#docker-ch3\"><span class=\"code\">DOCKER-03</span>compose — 이 스택 한 파일</a>\n  <a href=\"#docker-ch4\"><span class=\"code\">DOCKER-04</span>환경변수·설정 주입</a>\n  <a href=\"#docker-ch5\"><span class=\"code\">DOCKER-05</span>데이터 영속 — 볼륨</a>\n  <a href=\"#docker-ch6\"><span class=\"code\">DOCKER-06</span>서비스 간 네트워크</a>\n  <a href=\"#docker-ch7\"><span class=\"code\">DOCKER-07</span>헬스체크·기동 순서</a>\n  <a href=\"#docker-ch8\"><span class=\"code\">DOCKER-08</span>자주 쓰는 명령</a>\n  <a href=\"#docker-ch9\"><span class=\"code\">DOCKER-09</span>치트시트</a>\n  <a href=\"#doc-nginx\"><span class=\"code\">SRC</span>nginx 예시</a>\n<a href=\"#nginx-ch1\"><span class=\"code\">NGINX-01</span>리버스 프록시</a>\n  <a href=\"#nginx-ch2\"><span class=\"code\">NGINX-02</span>정적 파일·SPA</a>\n  <a href=\"#nginx-ch3\"><span class=\"code\">NGINX-03</span>TLS / HTTPS</a>\n  <a href=\"#nginx-ch4\"><span class=\"code\">NGINX-04</span>로드 밸런싱</a>\n  <a href=\"#nginx-ch5\"><span class=\"code\">NGINX-05</span>gzip·캐싱</a>\n  <a href=\"#nginx-ch6\"><span class=\"code\">NGINX-06</span>보안 헤더·rate limit</a>\n  <a href=\"#nginx-ch7\"><span class=\"code\">NGINX-07</span>운영 — 검증·리로드</a>\n  <a href=\"#nginx-ch8\"><span class=\"code\">NGINX-08</span>치트시트</a>",
  mainHtml: "<header class=\"hero\">\n  <div class=\"hero-serial\">\n    <span>DOC : ENGINEERING-PLATFORM-TOOLS</span>\n    <span>SCOPE : DOCKER · LINUX · VI · NGINX</span>\n    <span>LANG : KO</span>\n  </div>\n  <h1>플랫폼 도구와 운영 기본기</h1>\n  <p class=\"hero-sub\">Docker와 배포, Linux, vi, Docker 예시, nginx 예시를 실행 환경 관점으로 통합했습니다.</p>\n  <div class=\"hero-meta\">CURATED HANDBOOK PATH · SOURCES : 5 DOCUMENTS · UPDATED 2026-06</div>\n</header>\n\n<section id=\"bundle-index\">\n<div class=\"ch-head\"><span class=\"ch-code\">INDEX</span><h2>통합 문서</h2></div>\n<p class=\"lede\">아래 문서들을 한 페이지에서 이어 읽을 수 있도록 구성했습니다. 각 문서의 내부 목차는 왼쪽 목차에서 바로 이동할 수 있습니다.</p>\n<ul><li>Docker와 배포</li><li>리눅스</li><li>vi</li><li>Docker 예시</li><li>nginx 예시</li></ul>\n</section>\n\n<section id=\"doc-deploy\">\n<div class=\"ch-head\"><span class=\"ch-code\">SOURCE</span><h2>Docker와 배포</h2></div>\n</section>\n\n<header class=\"hero\">\n  <div class=\"hero-serial\">\n    <span>DOC : OPS-HANDBOOK-V1</span>\n    <span>SCOPE : CONTAINER · CI/CD · STRATEGY</span>\n    <span>LANG : KO</span>\n  </div>\n  <h1>Docker와 배포<br>핸드북</h1>\n  <p class=\"hero-sub\">컨테이너는 <strong>\"제 PC에선 됩니다\"</strong>를 끝냅니다 — 코드·런타임·의존성을 한 이미지로 봉인해 어디서나 같게 돕니다. 이 핸드북은 명령어 나열이 아니라 <em>왜 이렇게 도는가</em>를 먼저 잡습니다 — 레이어 캐시가 왜 그 순서를 강요하는지, 배포 전략 사이의 트레이드오프가 무엇인지, 어디서 깨지는지.</p>\n  <div class=\"hero-meta\">READER : 프론트엔드 기반 풀스택 확장 · Java/Spring Boot/JPA foundational<br>COMPILED : 2026-06</div>\n</header>\n\n<!-- ============ CH 1 ============ -->\n<section id=\"deploy-ch1\">\n<div class=\"ch-head\"><span class=\"ch-code\">OPS-01</span><h2>컨테이너란</h2></div>\n<p class=\"lede\">컨테이너의 핵심은 가상화가 아니라 <em>격리</em>입니다 — 하나의 OS 커널을 공유하면서, 프로세스가 자기만의 파일시스템·네트워크·프로세스 공간을 가진 것처럼 속이는 기술입니다. VM과 헷갈리면 무게도 한계도 잘못 잡게 됩니다.</p>\n<p>VM은 하이퍼바이저 위에 <strong>guest OS를 통째로</strong> 올립니다 — 커널, 시스템 데몬, 전부. 그래서 부팅에 수십 초가 걸리고 이미지가 기가바이트 단위입니다. 컨테이너는 그게 없습니다. host의 커널을 그대로 빌려 쓰고, Linux 커널의 두 기능으로 격리만 만듭니다 — <code>namespace</code>(무엇을 볼 수 있는가: PID·네트워크·마운트 공간 분리)와 <code>cgroup</code>(얼마나 쓸 수 있는가: CPU·메모리 한도). 그래서 컨테이너는 사실 <em>격리된 일반 프로세스</em>일 뿐입니다.</p>\n<table>\n<tr><th>축</th><th>가상머신(VM)</th><th>컨테이너</th></tr>\n<tr><td>격리 단위</td><td>guest OS 통째로 (커널 포함)</td><td>프로세스 (<code>namespace</code>·<code>cgroup</code>)</td></tr>\n<tr><td>커널</td><td>VM마다 독립 커널</td><td>host 커널 공유</td></tr>\n<tr><td>크기</td><td>GB 단위</td><td>MB 단위 (베이스에 따라 수~수백 MB)</td></tr>\n<tr><td>기동 시간</td><td>수십 초 (OS 부팅)</td><td>수백 ms (프로세스 시작)</td></tr>\n<tr><td>격리 강도</td><td>강함 (하드웨어 수준)</td><td>약함 (커널 공유 → 커널 취약점 공유)</td></tr>\n<tr><td>이식성</td><td>하이퍼바이저 의존</td><td>이미지 하나로 어디서나 동일</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">실패 모드 — 커널 공유의 함정</span>\n<p>컨테이너는 host 커널을 공유하므로, <em>커널이 다른 OS는 native로 못 돕니다</em>. macOS·Windows에서 Docker가 도는 건 사실 가벼운 Linux VM을 한 겹 깔고 그 안에서 컨테이너를 돌리는 것입니다 — 그래서 로컬(맥)과 서버(리눅스)의 동작이 미묘하게 다를 수 있습니다. 또 격리가 VM만큼 강하지 않으니, 멀티테넌트 환경에서 신뢰 못 할 코드를 돌릴 땐 컨테이너만으로 보안 경계를 삼지 마세요.</p>\n</div>\n</section>\n\n<!-- ============ CH 2 ============ -->\n<section id=\"deploy-ch2\">\n<div class=\"ch-head\"><span class=\"ch-code\">OPS-02</span><h2>이미지와 레이어</h2></div>\n<p class=\"lede\">세 단어를 정확히 구분하세요 — <em>이미지</em>는 불변 스냅샷(설계도), <em>레이어</em>는 그 이미지를 쌓아 올린 캐시 단위, <em>컨테이너</em>는 이미지를 실행한 인스턴스입니다. 클래스와 인스턴스의 관계를 떠올리면 정확합니다.</p>\n<p>이미지는 <strong>읽기 전용 레이어의 스택</strong>입니다. Dockerfile의 명령 하나(<code>RUN</code>, <code>COPY</code> 등)가 대체로 레이어 하나를 만들고, 각 레이어는 직전 상태에서 <em>바뀐 파일만</em> 담습니다. 컨테이너를 실행하면 이 읽기 전용 스택 위에 얇은 <strong>쓰기 가능 레이어</strong>가 한 장 얹히고, 실행 중 생기는 변경은 전부 거기로 갑니다. 컨테이너를 지우면 그 레이어도 사라집니다 — 그래서 상태는 컨테이너 안에 두면 안 됩니다(→ OPS-07).</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">LAYER STACK — 위로 갈수록 자주 바뀜</span>\n<span class=\"dim\">┌─────────────────────────────┐</span><br>\n<span class=\"dim\">│</span> <span class=\"seg\">RW 레이어</span> (컨테이너 실행 중 변경)  <span class=\"dim\">│ ← 컨테이너마다 1장</span><br>\n<span class=\"dim\">├─────────────────────────────┤</span><br>\n<span class=\"dim\">│</span> <span class=\"seg2\">COPY . .</span>  (앱 소스)            <span class=\"dim\">│ ← 매 빌드 바뀜</span><br>\n<span class=\"dim\">│</span> <span class=\"seg2\">RUN npm ci</span> (의존성)           <span class=\"dim\">│ ← 가끔 바뀜</span><br>\n<span class=\"dim\">│</span> <span class=\"seg2\">COPY package.json</span>            <span class=\"dim\">│ ← 드물게 바뀜</span><br>\n<span class=\"dim\">│</span> <span class=\"seg2\">FROM node:22-slim</span> (베이스)    <span class=\"dim\">│ ← 거의 안 바뀜</span><br>\n<span class=\"dim\">└─────────────────────────────┘  ↑ 읽기 전용, 공유·캐시됨</span>\n</div>\n<p>레이어가 캐시 단위라는 점이 빌드 속도의 전부를 결정합니다. Docker는 빌드 시 각 레이어를 위에서부터 검사해 <em>입력이 그대로면 캐시를 재사용</em>합니다. 그러나 한 레이어가 깨지면 그 <strong>아래(이후) 레이어는 전부 다시 빌드</strong>됩니다. 그래서 \"자주 바뀌는 것을 아래쪽(나중)에\" 두는 순서가 중요합니다(→ OPS-03). 여러 이미지가 같은 베이스 레이어를 쓰면 디스크에서 그 레이어를 <em>한 번만</em> 저장합니다 — content-addressable(해시 기반) 저장 덕입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">멘탈 모델</span>\n<p>이미지 : 컨테이너 = 클래스 : 인스턴스. 한 이미지에서 컨테이너 100개를 띄워도 읽기 전용 레이어는 공유되고, 각자 얇은 RW 레이어만 따로 가집니다. <code>docker images</code>로 이미지를, <code>docker ps</code>로 실행 중 컨테이너를, <code>docker history &lt;image&gt;</code>로 레이어 구성을 봅니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 3 ============ -->\n<section id=\"deploy-ch3\">\n<div class=\"ch-head\"><span class=\"ch-code\">OPS-03</span><h2>Dockerfile 기초·베스트 프랙티스</h2></div>\n<p class=\"lede\">Dockerfile은 이미지를 만드는 레시피입니다. 명령 몇 개만 알면 동작은 하지만, <em>순서와 선택</em>이 빌드 속도·이미지 크기·보안을 가릅니다.</p>\n<table>\n<tr><th>명령</th><th>역할 / 주의</th></tr>\n<tr><td><code>FROM</code></td><td>베이스 이미지 지정. 모든 Dockerfile의 첫 줄. 태그를 명시(<code>node:22-slim</code>)</td></tr>\n<tr><td><code>WORKDIR</code></td><td>이후 명령의 작업 디렉터리 설정(없으면 생성). <code>cd</code> 대신 이걸 쓴다</td></tr>\n<tr><td><code>COPY</code></td><td>host 파일을 이미지로 복사. <code>ADD</code>는 URL·자동 압축해제까지 하지만 의외성 때문에 보통 <code>COPY</code> 권장</td></tr>\n<tr><td><code>RUN</code></td><td>빌드 중 셸 명령 실행(레이어 생성). 패키지 설치·빌드 등</td></tr>\n<tr><td><code>CMD</code></td><td>컨테이너 기동 시 기본 명령. <code>docker run</code> 인자로 덮어쓸 수 있음</td></tr>\n<tr><td><code>ENTRYPOINT</code></td><td>고정 실행 진입점. <code>CMD</code>는 그 인자로 들어감 — 둘을 조합</td></tr>\n</table>\n<p>가장 큰 레버는 <strong>레이어 캐시를 살리는 명령 순서</strong>입니다. 의존성 설치(<code>npm ci</code>)는 소스 코드가 바뀌어도 <code>package.json</code>이 그대로면 다시 할 필요가 없습니다. 그래서 <em>의존성 매니페스트만 먼저 COPY → 설치 → 그다음 전체 소스 COPY</em> 순으로 짭니다. 이러면 코드 한 줄 고친 재빌드에서 의존성 설치 레이어가 캐시로 건너뛰어집니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">DOCKERFILE — Node 앱 (캐시·보안 고려)</span>\n<span class=\"seg\">FROM</span> node:22-slim<br>\n<span class=\"seg\">WORKDIR</span> /app<br>\n<span class=\"dim\"># 1) 의존성 매니페스트만 먼저 — 코드보다 드물게 바뀜</span><br>\n<span class=\"seg\">COPY</span> package.json package-lock.json ./<br>\n<span class=\"seg\">RUN</span> npm ci --omit=dev<br>\n<span class=\"dim\"># 2) 그다음 소스 — 자주 바뀌므로 캐시 경계를 여기 둔다</span><br>\n<span class=\"seg\">COPY</span> . .<br>\n<span class=\"dim\"># 3) 비root 유저로 강등 (slim 이미지는 node 유저 내장)</span><br>\n<span class=\"seg\">USER</span> node<br>\n<span class=\"seg\">EXPOSE</span> 3000<br>\n<span class=\"seg\">CMD</span> [<span class=\"seg2\">\"node\"</span>, <span class=\"seg2\">\"server.js\"</span>]\n</div>\n<p>두 가지를 더 챙깁니다. 첫째, <code>.dockerignore</code>로 <code>node_modules</code>·<code>.git</code>·로컬 빌드 산출물을 빌드 컨텍스트에서 제외하세요 — 안 그러면 거대한 컨텍스트를 daemon으로 통째로 전송하고, 로컬 <code>node_modules</code>가 이미지로 섞여 들어가 깨집니다. 둘째, <code>USER</code>로 <strong>비root</strong>로 떨어뜨리세요. 기본 root로 도는 컨테이너는 탈출 시 공격면이 커집니다.</p>\n<div class=\"callout warn\">\n<span class=\"co-label\">CMD vs ENTRYPOINT — 자주 틀리는 곳</span>\n<p><code>CMD</code>는 \"기본값\", <code>ENTRYPOINT</code>는 \"고정 실행파일\"입니다. <code>docker run myimg echo hi</code>를 하면 <code>CMD</code>는 통째로 <code>echo hi</code>로 교체되지만, <code>ENTRYPOINT</code>가 있으면 <code>echo hi</code>는 그 <em>인자</em>로 붙습니다. 또 <code>CMD node server.js</code>(셸 형식)는 <code>/bin/sh -c</code>로 감싸져 <strong>신호(SIGTERM)가 앱까지 안 전달</strong>될 수 있습니다 — graceful shutdown이 깨지는 단골 원인입니다. <code>CMD [\"node\",\"server.js\"]</code>(exec 배열 형식)을 쓰세요(→ OPS-05의 신호 처리).</p>\n</div>\n</section>\n\n<!-- ============ CH 4 ============ -->\n<section id=\"deploy-ch4\">\n<div class=\"ch-head\"><span class=\"ch-code\">OPS-04</span><h2>멀티스테이지 빌드와 이미지 최적화</h2></div>\n<p class=\"lede\">빌드에 필요한 것과 실행에 필요한 것은 다릅니다. 컴파일러·devDependencies·빌드 캐시는 <em>실행 시점엔 쓰레기</em>입니다. 멀티스테이지 빌드는 이 둘을 분리해 최종 이미지에서 빌드 도구를 통째로 들어냅니다.</p>\n<p>핵심 문법은 하나입니다 — Dockerfile 안에 <code>FROM</code>을 여러 번 써서 단계(stage)를 나누고, <code>COPY --from=&lt;stage&gt;</code>로 <em>앞 단계의 결과물만</em> 다음 단계로 가져옵니다. 빌드 단계는 무거운 SDK를 다 깔아 빌드하고, 런타임 단계는 가벼운 베이스에 산출물만 얹습니다. 빌드 단계는 최종 이미지에 포함되지 않습니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">MULTI-STAGE — 빌드 / 런타임 분리</span>\n<span class=\"dim\"># --- 1단계: 빌드 (무거운 SDK 포함) ---</span><br>\n<span class=\"seg\">FROM</span> node:22 <span class=\"seg2\">AS</span> build<br>\n<span class=\"seg\">WORKDIR</span> /app<br>\n<span class=\"seg\">COPY</span> package.json package-lock.json ./<br>\n<span class=\"seg\">RUN</span> npm ci<br>\n<span class=\"seg\">COPY</span> . .<br>\n<span class=\"seg\">RUN</span> npm run build <span class=\"dim\"># → /app/dist 생성</span><br>\n<br>\n<span class=\"dim\"># --- 2단계: 런타임 (가벼운 베이스, 산출물만) ---</span><br>\n<span class=\"seg\">FROM</span> node:22-slim<br>\n<span class=\"seg\">WORKDIR</span> /app<br>\n<span class=\"seg\">COPY</span> --from=build <span class=\"seg2\">/app/dist</span> ./dist<br>\n<span class=\"seg\">COPY</span> --from=build <span class=\"seg2\">/app/node_modules</span> ./node_modules<br>\n<span class=\"seg\">USER</span> node<br>\n<span class=\"seg\">CMD</span> [<span class=\"seg2\">\"node\"</span>, <span class=\"seg2\">\"dist/server.js\"</span>]\n</div>\n<p>베이스 이미지 선택이 크기와 공격면을 함께 줄입니다. <code>node:22</code>(full, ~1GB)보다 <code>node:22-slim</code>(~200MB)이, 더 극단적으로는 <code>distroless</code>(셸·패키지매니저조차 없는 최소 런타임)나 Alpine 계열이 있습니다. 작을수록 <em>다운로드·기동이 빠르고, 깔린 패키지가 적으니 CVE 노출도 줄어듭니다</em>.</p>\n<table>\n<tr><th>베이스</th><th>크기 감</th><th>트레이드오프</th></tr>\n<tr><td><code>node:22</code> (full)</td><td>크다 (~1GB)</td><td>디버깅 편함(셸·도구 다 있음), 그러나 무겁고 공격면 큼</td></tr>\n<tr><td><code>node:22-slim</code></td><td>중간 (~200MB)</td><td>실전 기본값. glibc 기반이라 호환성 무난</td></tr>\n<tr><td>Alpine</td><td>작다 (~50MB)</td><td>musl libc — native 모듈 빌드 이슈가 가끔 터짐</td></tr>\n<tr><td>distroless</td><td>가장 작다</td><td>셸 없음 → <code>docker exec</code> 디버깅 불가, 보안 최상</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">왜 효과가 큰가</span>\n<p>멀티스테이지의 진짜 이득은 크기보다 <em>분리된 관심사</em>입니다 — 빌드 도구(컴파일러·devDeps)가 production 이미지에 절대 못 들어가니, 공급망 공격면이 구조적으로 줄어듭니다. 디버깅이 어려운 distroless가 부담되면 slim에서 출발하고, 이미지 취약점은 <code>docker scout</code>나 <code>trivy</code> 같은 스캐너로 CI에서 점검하세요(→ OPS-08).</p>\n</div>\n</section>\n\n<!-- ============ CH 5 ============ -->\n<section id=\"deploy-ch5\">\n<div class=\"ch-head\"><span class=\"ch-code\">OPS-05</span><h2>컨테이너 실행과 구성</h2></div>\n<p class=\"lede\">이미지를 만들었으면 이제 <em>돌립니다</em>. 실행 시점의 4대 구성 축 — 포트·볼륨·환경변수·네트워크 — 만 잡으면 로컬에서 운영까지 같은 그림으로 다룹니다.</p>\n<table>\n<tr><th>축</th><th>플래그 / 의미</th></tr>\n<tr><td>포트 매핑</td><td><code>-p 3000:3000</code> — host:container. 컨테이너 안의 포트를 밖으로 노출</td></tr>\n<tr><td>볼륨</td><td><code>-v ./data:/app/data</code> — 컨테이너 밖에 상태 보존(named volume / bind mount)</td></tr>\n<tr><td>환경변수</td><td><code>-e NODE_ENV=production</code> 또는 <code>--env-file .env</code> — 설정 주입(→ OPS-07)</td></tr>\n<tr><td>네트워크</td><td><code>--network mynet</code> — 같은 네트워크의 컨테이너끼리 이름으로 통신</td></tr>\n<tr><td>실행/정리</td><td><code>-d</code>(백그라운드) <code>--rm</code>(종료 시 삭제) <code>--name</code>(이름 부여)</td></tr>\n</table>\n<p>로컬에서 DB·API·캐시 여러 서비스를 동시에 띄워야 하면 <code>docker run</code>을 손으로 여러 번 치는 대신 <strong>Docker Compose</strong>를 씁니다 — <code>compose.yaml</code>에 서비스·네트워크·볼륨을 선언하고 <code>docker compose up</code> 한 번으로 전부 띄웁니다. Compose가 자동으로 네트워크를 만들어, 서비스끼리 <em>서비스 이름을 호스트명처럼</em> 부를 수 있습니다(예: 앱에서 DB 호스트를 <code>db</code>로).</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">compose.yaml — 앱 + Postgres</span>\n<span class=\"seg2\">services:</span><br>\n&nbsp;&nbsp;<span class=\"seg\">app:</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;build: .<br>\n&nbsp;&nbsp;&nbsp;&nbsp;ports: [<span class=\"seg2\">\"3000:3000\"</span>]<br>\n&nbsp;&nbsp;&nbsp;&nbsp;environment:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;DATABASE_URL: postgres://app:pw@<span class=\"seg\">db</span>:5432/app<br>\n&nbsp;&nbsp;&nbsp;&nbsp;depends_on: [db]<br>\n&nbsp;&nbsp;<span class=\"seg\">db:</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;image: postgres:16<br>\n&nbsp;&nbsp;&nbsp;&nbsp;environment:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;POSTGRES_PASSWORD: pw<br>\n&nbsp;&nbsp;&nbsp;&nbsp;volumes: [<span class=\"seg2\">\"pgdata:/var/lib/postgresql/data\"</span>] <span class=\"dim\"># 상태 보존</span><br>\n<span class=\"seg2\">volumes:</span><br>\n&nbsp;&nbsp;pgdata:\n</div>\n<div class=\"callout warn\">\n<span class=\"co-label\">신호와 graceful shutdown</span>\n<p>오케스트레이터(또는 <code>docker stop</code>)는 컨테이너에 <code>SIGTERM</code>을 보내고, 유예 시간(기본 10초) 안에 안 죽으면 <code>SIGKILL</code>로 강제 종료합니다. 앱이 PID 1로 돌면서 신호를 직접 처리해야 진행 중 요청을 마저 끝내고 연결을 정리합니다. <code>CMD</code>를 셸 형식으로 쓰면 신호가 <code>sh</code>에서 막혀 앱까지 안 갑니다(→ OPS-03). exec 배열 형식을 쓰고, 필요하면 <code>--init</code>으로 가벼운 init을 PID 1에 두세요.</p>\n</div>\n</section>\n\n<!-- ============ CH 6 ============ -->\n<section id=\"deploy-ch6\">\n<div class=\"ch-head\"><span class=\"ch-code\">OPS-06</span><h2>레지스트리와 태깅</h2></div>\n<p class=\"lede\">레지스트리는 이미지의 <em>원격 저장소</em>입니다 — git의 GitHub에 해당합니다. 로컬에서 빌드한 이미지를 <code>push</code>하고, 서버·CI가 <code>pull</code>해 실행합니다. 그 사이를 잇는 건 <strong>태그</strong>이고, 태그 전략이 배포 추적성을 좌우합니다.</p>\n<table>\n<tr><th>동작</th><th>명령 / 의미</th></tr>\n<tr><td>로그인</td><td><code>docker login &lt;registry&gt;</code> — Docker Hub, GHCR, AWS ECR 등</td></tr>\n<tr><td>태깅</td><td><code>docker tag app:local ghcr.io/org/app:1.4.2</code> — 레지스트리 경로 + 버전</td></tr>\n<tr><td>업로드</td><td><code>docker push ghcr.io/org/app:1.4.2</code> — 레이어 단위로 전송(있는 건 건너뜀)</td></tr>\n<tr><td>다운로드</td><td><code>docker pull ghcr.io/org/app:1.4.2</code> — 서버·CI가 가져와 실행</td></tr>\n</table>\n<p>태그 이름은 <code>레지스트리/네임스페이스/이미지:태그</code> 구조입니다. 태그는 같은 이미지에 여러 개 붙일 수 있는 <em>가변 포인터</em>입니다 — 진짜 불변 식별자는 내용 해시인 <strong>digest</strong>(<code>@sha256:...</code>)입니다. 버전 태그는 사람이 읽기 위한 것이고, \"정확히 이 이미지\"를 못 박으려면 digest로 고정합니다.</p>\n<div class=\"callout risk\">\n<span class=\"co-label\">안티패턴 — latest 태그</span>\n<p><code>latest</code>는 \"최신\"을 보장하지 않습니다 — 그저 태그를 안 붙이면 붙는 <em>기본 문자열</em>일 뿐입니다. production에서 <code>latest</code>로 배포하면 ① 지금 도는 게 어떤 커밋인지 추적 불가 ② 재시작·스케일아웃 시 노드마다 다른 이미지를 당겨와 버전이 갈라짐 ③ 롤백 대상이 모호해집니다. <strong>커밋 SHA나 시맨틱 버전(<code>1.4.2</code>)으로 불변 태깅</strong>하고, production 배포는 digest 고정을 권합니다. <code>latest</code>는 로컬 편의용으로만.</p>\n</div>\n</section>\n\n<!-- ============ CH 7 ============ -->\n<section id=\"deploy-ch7\">\n<div class=\"ch-head\"><span class=\"ch-code\">OPS-07</span><h2>12-factor 앱</h2></div>\n<p class=\"lede\">12-factor는 \"컨테이너·클라우드에서 잘 도는 앱\"의 설계 원칙 모음입니다. 전부 외울 필요는 없고, 컨테이너 배포에 직결되는 네 가지만 몸에 익히면 대부분의 사고를 피합니다.</p>\n<table>\n<tr><th>원칙</th><th>무엇을 / 왜</th></tr>\n<tr><td>설정 = 환경변수</td><td>DB URL·시크릿·플래그를 <em>코드 밖</em> 환경변수로. 같은 이미지를 dev/stage/prod에 그대로 재사용</td></tr>\n<tr><td>stateless 프로세스</td><td>프로세스는 상태를 안 가짐 — 세션·파일은 외부(DB·오브젝트 스토리지)로. 아무 인스턴스나 죽고 늘어도 무방</td></tr>\n<tr><td>로그 = stdout 스트림</td><td>앱은 파일에 안 쓰고 <code>stdout</code>으로 흘려보냄. 수집·라우팅은 플랫폼이 담당</td></tr>\n<tr><td>빌드/릴리즈/실행 분리</td><td>코드→이미지(빌드), 이미지+설정(릴리즈), 그 릴리즈 실행(실행)을 단계로 분리 → 롤백은 이전 릴리즈로</td></tr>\n</table>\n<p>왜 이게 컨테이너와 맞물리나. 컨테이너의 RW 레이어는 <em>휘발성</em>입니다(→ OPS-02) — 컨테이너가 죽으면 안에 쓴 파일은 사라집니다. 그러니 상태를 안에 두면 안 되고(stateless), 로그를 파일로 쓰면 수집 전에 증발합니다(stdout). 설정을 이미지에 굽으면 환경마다 이미지를 새로 빌드해야 하니, 환경변수로 빼서 <em>한 이미지를 모든 환경에서</em> 재사용합니다. 이 셋이 맞물려야 수평 확장·무중단 배포·빠른 롤백이 성립합니다.</p>\n<div class=\"callout warn\">\n<span class=\"co-label\">실패 모드 — 상태를 컨테이너에 둔 경우</span>\n<p>업로드 파일을 컨테이너 로컬 디스크에 저장하면, 스케일아웃해 인스턴스가 2개가 되는 순간 \"방금 올린 파일이 안 보임\"이 됩니다 — 요청이 다른 인스턴스로 갔기 때문입니다. 배포로 컨테이너가 교체되면 통째로 사라지기도 합니다. 파일은 S3 같은 외부 스토리지로, 세션은 Redis·DB로 빼야 합니다. 시크릿을 환경변수로 넣을 땐 <code>docker inspect</code>·로그에 노출되지 않게 secret manager 사용을 고려하세요(→ OPS-08의 시크릿 주입).</p>\n</div>\n</section>\n\n<!-- ============ CH 8 ============ -->\n<section id=\"deploy-ch8\">\n<div class=\"ch-head\"><span class=\"ch-code\">OPS-08</span><h2>CI/CD 파이프라인</h2></div>\n<p class=\"lede\">CI(지속적 통합)는 코드가 합쳐질 때마다 자동으로 빌드·테스트하는 것, CD(지속적 배포)는 그 결과물을 자동으로 환경에 올리는 것입니다. 컨테이너가 CI/CD와 잘 맞는 이유는 <em>빌드 산출물이 이미지 하나</em>로 떨어져 그대로 배포되기 때문입니다 — 빌드와 배포 사이에 변형이 없습니다.</p>\n<div class=\"flow\">\n<span class=\"step\">commit / PR</span><span class=\"arr\">→</span>\n<span class=\"step\">빌드</span><span class=\"arr\">→</span>\n<span class=\"step\">테스트 · 스캔</span><span class=\"arr\">→</span>\n<span class=\"step hl\">이미지 빌드 · push</span><span class=\"arr\">→</span>\n<span class=\"step\">배포 (deploy)</span><span class=\"arr\">→</span>\n<span class=\"step\">헬스체크</span>\n</div>\n<p>각 단계 사이에는 <strong>게이트(gate)</strong>가 있습니다 — 테스트가 깨지면 거기서 멈추고 배포로 못 넘어갑니다. production 배포 앞에는 보통 사람의 수동 승인 게이트를 둡니다. 단계가 통과할 때마다 신뢰가 쌓이고, 깨지면 가장 싼 단계(테스트)에서 빨리 잡힙니다 — 이게 게이트의 핵심 가치입니다.</p>\n<table>\n<tr><th>단계</th><th>하는 일</th></tr>\n<tr><td>빌드</td><td>의존성 설치·컴파일. 캐시로 빠르게</td></tr>\n<tr><td>테스트</td><td>unit·integration. 실패 시 즉시 중단(게이트)</td></tr>\n<tr><td>스캔</td><td>이미지 취약점(<code>trivy</code>)·lint·SAST. 보안 게이트</td></tr>\n<tr><td>이미지 빌드·push</td><td>커밋 SHA로 태깅해 레지스트리에 push(→ OPS-06)</td></tr>\n<tr><td>배포</td><td>그 이미지를 환경에 롤아웃(전략은 → OPS-09)</td></tr>\n</table>\n<p><strong>GitOps</strong>는 한 걸음 더 갑니다 — 배포 상태를 명령으로 밀어넣는 대신, <em>원하는 상태를 git 저장소에 선언</em>하고 에이전트(예: Argo CD·Flux)가 실제 클러스터를 그 선언에 맞춰 끌어옵니다. git이 단일 진실 공급원이 되어, 배포 이력이 곧 git 이력이고 롤백은 revert입니다.</p>\n<div class=\"callout risk\">\n<span class=\"co-label\">시크릿 주입 — 절대 이미지에 굽지 마라</span>\n<p>API 키·DB 비밀번호를 Dockerfile의 <code>ENV</code>나 <code>COPY .env</code>로 넣으면 <em>이미지 레이어에 영구히 박혀</em>, 레지스트리에 접근 가능한 누구나 <code>docker history</code>로 꺼낼 수 있습니다 — 나중에 덮어써도 이전 레이어에 남습니다. 시크릿은 ① CI의 secret store(GitHub Actions Secrets 등)에서 빌드 시점에만 주입하거나 ② 런타임에 secret manager(Vault·클라우드 KMS)·오케스트레이터 시크릿으로 환경변수에 넣습니다. 빌드 중 일시적으로 필요하면 BuildKit의 <code>--mount=type=secret</code>으로 레이어에 안 남게 하세요.</p>\n</div>\n</section>\n\n<!-- ============ CH 9 ============ -->\n<section id=\"deploy-ch9\">\n<div class=\"ch-head\"><span class=\"ch-code\">OPS-09</span><h2>배포 전략</h2></div>\n<p class=\"lede\">\"새 버전으로 어떻게 갈아끼우는가\"의 문제입니다. 핵심 목표는 셋 — <em>무중단</em>(사용자가 끊김을 못 느낌), <em>빠른 롤백</em>(문제 시 즉시 되돌림), <em>위험 통제</em>(나쁜 버전의 폭발 반경 최소화). 전략마다 이 셋의 균형이 다릅니다.</p>\n<table>\n<tr><th>전략</th><th>방식</th><th>장점 / 트레이드오프</th></tr>\n<tr><td>롤링(rolling)</td><td>인스턴스를 몇 개씩 순차 교체</td><td>추가 자원 거의 없음 / 교체 중 신·구 버전 공존, 롤백이 느림</td></tr>\n<tr><td>블루그린</td><td>구(blue)·신(green) 환경을 통째로 띄워두고 트래픽을 한 번에 전환</td><td>즉시 전환·즉시 롤백(되돌리기=스위치 back) / 자원 2배, DB 마이그레이션 호환 필요</td></tr>\n<tr><td>카나리</td><td>신 버전에 트래픽을 5%→25%→100%로 점증, 지표 보며 확대</td><td>폭발 반경 최소·실데이터 검증 / 설정 복잡, 관측·자동 롤백 인프라 필요</td></tr>\n</table>\n<p>세 전략 모두 <strong>헬스체크</strong>가 안전판입니다. 새 인스턴스가 트래픽을 받기 전, 오케스트레이터는 <code>readiness</code> 프로브로 \"받을 준비 됐는지\"를 확인합니다 — 준비 안 된 인스턴스로 트래픽이 가지 않게. <code>liveness</code> 프로브는 \"죽었는지\"를 보고 죽었으면 재시작합니다. 카나리의 자동 확대·롤백은 이 헬스체크와 에러율·레이턴시 지표에 묶입니다(→ 로깅·모니터링·장애대응).</p>\n<div class=\"callout warn\">\n<span class=\"co-label\">트레이드오프 — DB 마이그레이션이 발목을 잡는다</span>\n<p>무중단 배포의 진짜 난점은 코드가 아니라 <em>스키마</em>입니다. 신·구 버전이 잠깐 공존하므로(롤링·카나리·블루그린 전환 순간), DB 스키마 변경은 <strong>양쪽 버전과 모두 호환</strong>돼야 합니다 — 컬럼 삭제·이름변경 같은 파괴적 변경을 코드 배포와 한 번에 하면 한쪽이 깨집니다. expand-and-contract 패턴(컬럼 추가→양쪽 호환 코드 배포→구 컬럼 제거를 다음 릴리즈로)으로 나눠야 안전합니다. 블루그린에서 green이 prod DB를 공유하면 \"환경 통째 분리\"의 환상이 여기서 깨집니다(→ 백엔드 개요의 트랜잭션·마이그레이션).</p>\n</div>\n</section>\n\n<!-- ============ CH 10 ============ -->\n<section id=\"deploy-ch10\">\n<div class=\"ch-head\"><span class=\"ch-code\">OPS-10</span><h2>오케스트레이션 개요</h2></div>\n<p class=\"lede\">컨테이너 하나를 돌리는 건 <code>docker run</code>으로 끝입니다. 그러나 수십~수백 개를 여러 서버에 걸쳐 <em>띄우고·살피고·죽으면 되살리고·확장하고·배포</em>하는 건 손으로 못 합니다. 이걸 자동화하는 게 오케스트레이션이고, 사실상 표준이 <strong>Kubernetes(K8s)</strong>입니다.</p>\n<p>K8s를 왜 쓰나 — 핵심은 <em>선언적 자가복구</em>입니다. \"이 앱을 3개 띄워라\"라고 원하는 상태를 선언하면, K8s가 실제 상태를 거기에 맞춰 계속 끌어옵니다. 노드가 죽어 컨테이너가 2개로 줄면 자동으로 1개를 다른 노드에 다시 띄웁니다. 명령(어떻게)이 아니라 상태(무엇을)를 다룬다는 점이 OPS-08의 GitOps와 맞물립니다.</p>\n<table>\n<tr><th>리소스</th><th>역할 (개념만)</th></tr>\n<tr><td>Pod</td><td>배포의 최소 단위 — 컨테이너 1개(때로 몇 개)를 묶음. 가장 작은 \"실행 단위\"</td></tr>\n<tr><td>Deployment</td><td>Pod를 <em>몇 개</em> 유지할지 선언·관리. 롤링 업데이트·롤백을 담당</td></tr>\n<tr><td>Service</td><td>바뀌는 Pod들 앞의 안정적 진입점(가상 IP·DNS) — 로드밸런싱</td></tr>\n<tr><td>Ingress</td><td>클러스터 외부 HTTP(S) 트래픽을 내부 Service로 라우팅(도메인·경로 기반)</td></tr>\n</table>\n<div class=\"callout gm\">\n<span class=\"co-label\">범위 — 여기까지만</span>\n<p>K8s의 깊이(스케줄링·네트워킹·오퍼레이터·헬름·RBAC 등)는 이 핸드북의 범위 밖입니다. 지금 필요한 건 <em>왜 존재하고 핵심 개념이 무엇인지</em>까지입니다 — Pod/Deployment/Service/Ingress 네 단어의 관계만 잡으면 팀의 매니페스트를 읽고 대화에 참여할 수 있습니다. 작은 서비스라면 K8s가 과합니다 — 관리형 PaaS(Cloud Run·ECS·Fly.io 등)나 Compose로 충분한 경우가 많고, 복잡성 비용을 정당화할 규모가 됐을 때 K8s로 갑니다. 실제 운영 디테일은 → 로깅·모니터링·장애대응, 백엔드 개요와 함께 보세요.</p>\n</div>\n</section>\n\n<!-- ============ CH 11 ============ -->\n<section id=\"deploy-ch11\">\n<div class=\"ch-head\"><span class=\"ch-code\">OPS-11</span><h2>용어집</h2></div>\n<p class=\"lede\">이 핸드북에서 반복된 핵심 용어. 정의를 한 줄로 못 줄이면 아직 이해 못 한 것입니다 — 막힐 때 여기로.</p>\n<div class=\"glossary\">\n<div class=\"g-row\"><div class=\"g-term\"><b>컨테이너</b><span>container</span></div><div class=\"g-def\"><code>namespace</code>·<code>cgroup</code>로 격리된 프로세스. host 커널을 공유하는 이미지의 실행 인스턴스(→ OPS-01)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>이미지</b><span>image</span></div><div class=\"g-def\">코드·런타임·의존성을 봉인한 불변(read-only) 스냅샷. 컨테이너의 \"클래스\"에 해당(→ OPS-02)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>레이어</b><span>layer</span></div><div class=\"g-def\">이미지를 구성하는 읽기 전용 스택의 한 장 = 캐시·공유 단위. Dockerfile 명령 하나가 대체로 한 장(→ OPS-02)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>Dockerfile</b><span>build recipe</span></div><div class=\"g-def\">이미지를 만드는 명령 스크립트. <code>FROM</code>/<code>RUN</code>/<code>COPY</code>/<code>CMD</code> 등. 순서가 캐시·크기를 결정(→ OPS-03)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>.dockerignore</b><span>build context</span></div><div class=\"g-def\">빌드 컨텍스트에서 제외할 파일 목록. <code>node_modules</code>·<code>.git</code> 제외로 전송량·오염 방지(→ OPS-03)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>멀티스테이지 빌드</b><span>multi-stage</span></div><div class=\"g-def\">한 Dockerfile에 빌드·런타임 단계를 나눠, 산출물만 <code>COPY --from</code>으로 가져옴. 크기·공격면↓(→ OPS-04)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>distroless / slim</b><span>minimal base</span></div><div class=\"g-def\">패키지를 최소화한 베이스 이미지. 작고 안전하지만 디버깅 도구가 적거나 없음(→ OPS-04)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>볼륨</b><span>volume</span></div><div class=\"g-def\">컨테이너 밖에 상태를 보존하는 마운트. 휘발성 RW 레이어 문제를 우회(→ OPS-05, OPS-07)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>Compose</b><span>docker compose</span></div><div class=\"g-def\">여러 컨테이너를 <code>compose.yaml</code>로 선언해 한 번에 띄우는 로컬 다중 서비스 도구(→ OPS-05)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>레지스트리</b><span>registry</span></div><div class=\"g-def\">이미지의 원격 저장소. <code>push</code>/<code>pull</code>로 주고받음(Docker Hub·GHCR·ECR)(→ OPS-06)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>태그 / digest</b><span>tag · @sha256</span></div><div class=\"g-def\">태그는 가변 포인터(<code>1.4.2</code>), digest는 내용 해시로 고정한 불변 식별자. <code>latest</code>는 안티패턴(→ OPS-06)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>12-factor</b><span>config·stateless·logs</span></div><div class=\"g-def\">클라우드 친화 앱 설계 원칙. 설정=환경변수, stateless, 로그=stdout, 빌드/릴리즈/실행 분리(→ OPS-07)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>CI/CD</b><span>pipeline</span></div><div class=\"g-def\">빌드→테스트→이미지→배포를 게이트로 자동화. 산출물=이미지 하나라 변형 없이 배포(→ OPS-08)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>GitOps</b><span>declarative deploy</span></div><div class=\"g-def\">원하는 상태를 git에 선언하고 에이전트가 클러스터를 동기화. 롤백=revert(→ OPS-08, OPS-10)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>롤링</b><span>rolling update</span></div><div class=\"g-def\">인스턴스를 순차 교체하는 무중단 배포. 자원 절약하나 신·구 공존·롤백 느림(→ OPS-09)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>블루그린</b><span>blue-green</span></div><div class=\"g-def\">신·구 환경을 통째로 띄워두고 트래픽을 한 번에 전환. 즉시 롤백, 자원 2배(→ OPS-09)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>카나리</b><span>canary</span></div><div class=\"g-def\">신 버전에 트래픽을 점증하며 지표 관찰. 폭발 반경 최소, 관측 인프라 필요(→ OPS-09)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>헬스체크</b><span>readiness · liveness</span></div><div class=\"g-def\">readiness=트래픽 받을 준비됐나, liveness=살아있나. 무중단 배포의 안전판(→ OPS-09)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>Kubernetes</b><span>K8s</span></div><div class=\"g-def\">선언적 자가복구 오케스트레이터. 원하는 상태를 선언하면 실제 상태를 맞춰줌(→ OPS-10)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>Pod / Deployment</b><span>K8s 리소스</span></div><div class=\"g-def\">Pod=실행 최소 단위(컨테이너 묶음), Deployment=Pod 개수·롤링·롤백 관리(→ OPS-10)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>Service / Ingress</b><span>K8s 네트워킹</span></div><div class=\"g-def\">Service=Pod 앞 안정적 진입점·LB, Ingress=외부 HTTP를 내부 Service로 라우팅(→ OPS-10)</div></div>\n</div>\n<div class=\"callout gm\">\n<span class=\"co-label\">학습 순서 제안</span>\n<p>전부 한 번에 익히려 하지 마세요. 먼저 손에 붙일 것: <code>docker build</code> → <code>docker run -p</code> → 멀티스테이지 Dockerfile 한 장 → <code>docker compose up</code>으로 로컬 풀스택. 이 네 단계로 OPS-01~05가 몸에 들어옵니다. 그다음 CI에서 이미지를 빌드·push해보고(OPS-06·08), 배포 전략(OPS-09)은 팀의 실제 파이프라인을 읽으며 익히세요. K8s(OPS-10)는 규모가 정당화할 때 갑니다 — 그전엔 개념만으로 충분합니다. 런타임 관측은 → 로깅·모니터링·장애대응, 데이터 계층은 → 백엔드 개요와 함께.</p>\n</div>\n</section>\n\n<section id=\"deploy-ch12\">\n<div class=\"ch-head\"><span class=\"ch-code\">OPS-12</span><h2>운영 가능한 배포 심화</h2></div>\n<p class=\"lede\">배포는 이미지를 올리는 일이 아니라 트래픽 전환, 종료 처리, 설정 일관성, 롤백 가능성을 관리하는 일입니다.</p>\n<table>\n<tr><th>주제</th><th>실무 기준</th><th>실패 신호</th></tr>\n<tr><td>graceful shutdown</td><td>SIGTERM을 받으면 새 요청을 막고 진행 중 요청을 마무리</td><td>배포 때 간헐적인 502/connection reset 발생</td></tr>\n<tr><td>readiness</td><td>트래픽을 받아도 되는 상태인지 확인</td><td>앱 시작 직후 DB 연결 전부터 트래픽 유입</td></tr>\n<tr><td>liveness</td><td>프로세스가 복구 불능 상태인지 확인</td><td>느린 의존성 때문에 정상 앱이 계속 재시작</td></tr>\n<tr><td>config drift</td><td>환경별 설정 차이를 코드/템플릿으로 추적</td><td>운영만 수동 hotfix 설정이 남아 재현 불가</td></tr>\n<tr><td>rollback</td><td>앱, DB, 메시지 schema가 되돌릴 수 있는지 사전 확인</td><td>배포 후 DB 변경 때문에 이전 버전이 실행 불가</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">Case study</span>\n<p>롤링 배포 중 새 컨테이너가 뜨자마자 readiness가 성공하면 아직 connection pool이 준비되지 않은 상태에서 요청이 들어올 수 있습니다. startup probe, readiness probe, graceful shutdown, termination grace period를 함께 설계해야 배포 중 오류율을 낮출 수 있습니다.</p>\n</div>\n</section>\n\n<footer>\nDOCKER & DEPLOY HANDBOOK · V1 · 2026-06<br>\nSCOPE : CONTAINER · CI/CD · DEPLOYMENT STRATEGY · READER : FE → FULLSTACK<br>\nNOTE : 명령·문법은 실재 Docker 기준 · COMPANION : LINUX/SHELL · BACKEND ENGINEERING · LOGGING/MONITORING HANDBOOK\n</footer>\n\n<section id=\"doc-linux\">\n<div class=\"ch-head\"><span class=\"ch-code\">SOURCE</span><h2>리눅스</h2></div>\n</section>\n\n<header class=\"hero\">\n  <div class=\"hero-serial\">\n    <span>DOC : LX-HANDBOOK-V1</span>\n    <span>ENV : macOS(Darwin) · zsh · mise · chezmoi</span>\n    <span>LANG : KO</span>\n  </div>\n  <h1>리눅스 / 셸 명령어<br>핸드북</h1>\n  <p class=\"hero-sub\">명령어 암기가 아니라 <strong>사고 모델</strong>을 먼저 잡습니다 — 모든 명령은 텍스트 스트림을 입력받아 텍스트 스트림을 내보내고, 작은 도구들을 파이프로 조립해 큰 일을 합니다. 이 한 가지 철학을 이해하면 나머지는 조합입니다. 네 환경(macOS·zsh·mise·chezmoi)과 모던 CLI(rg·fd·bat) 기준.</p>\n  <div class=\"hero-meta\">NOTE : macOS는 BSD 계열 — 일부 플래그가 GNU(Linux)와 다름. 차이 나는 곳은 표기함<br>COMPILED : 2026-06</div>\n</header>\n\n<!-- ============ CH 1 ============ -->\n<section id=\"linux-ch1\">\n<div class=\"ch-head\"><span class=\"ch-code\">LX-01</span><h2>셸의 사고 모델</h2></div>\n<p class=\"lede\">Unix 철학 한 줄: <em>\"한 가지를 잘하는 작은 프로그램을, 텍스트 스트림으로 잇는다.\"</em> 명령어를 외우기 전에 이 구조를 잡으면, 처음 보는 명령도 같은 문법으로 읽힙니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">ANATOMY OF A COMMAND</span>\n<span class=\"seg\">command</span> <span class=\"seg2\">-옵션 --긴옵션</span> <span class=\"dim\">인자(파일·경로)</span><br>\n<span class=\"dim\">예:</span> ls <span class=\"seg2\">-la</span> <span class=\"dim\">~/projects</span><br>\n<br>\n<span class=\"sc-label\">THREE STREAMS</span>\nstdin(0) ──▶ [ <span class=\"seg\">프로그램</span> ] ──▶ stdout(1)<br>\n<span class=\"dim\">                  └──▶ stderr(2)  ← 에러는 별도 채널</span>\n</div>\n<p>모든 프로세스엔 세 개의 표준 스트림이 있습니다 — 입력(<code>stdin</code>), 정상 출력(<code>stdout</code>), 에러 출력(<code>stderr</code>). 이게 분리돼 있어서 <em>정상 결과는 파일로 저장하면서 에러는 화면에 띄우는</em> 식의 조합이 가능합니다(→ LX-08). 그리고 모든 명령은 끝나면 <strong>종료코드(exit code)</strong>를 남깁니다 — <code>0</code>은 성공, 그 외는 실패. <code>echo $?</code>로 직전 명령의 종료코드를 보고, <code>&amp;&amp;</code>/<code>||</code>로 성공·실패에 따라 다음을 잇습니다.</p>\n<table>\n<tr><th>도움 받기</th><th>의미</th></tr>\n<tr><td><code>man ls</code></td><td>매뉴얼 페이지 (<code>q</code>로 종료, <code>/단어</code>로 검색)</td></tr>\n<tr><td><code>ls --help</code></td><td>간단 사용법 (대부분의 GNU 도구)</td></tr>\n<tr><td><code>tldr ls</code></td><td>예제 중심 요약 (별도 설치 — 실전에 가장 빠름)</td></tr>\n<tr><td><code>which ls</code> · <code>type ls</code></td><td>이 명령이 어디 있는지 / alias·함수인지</td></tr>\n</table>\n</section>\n\n<!-- ============ CH 2 ============ -->\n<section id=\"linux-ch2\">\n<div class=\"ch-head\"><span class=\"ch-code\">LX-02</span><h2>탐색·이동</h2></div>\n<p class=\"lede\">디렉터리 트리 안에서 \"지금 어디고, 뭐가 있고, 어디로 갈까\". 가장 자주 치는 명령들이라 손에 붙여둘 가치가 큽니다.</p>\n<table>\n<tr><th>명령</th><th>의미 / 자주 쓰는 형태</th></tr>\n<tr><td><code>pwd</code></td><td>현재 경로 출력</td></tr>\n<tr><td><code>ls -la</code></td><td>숨김파일 포함(<code>-a</code>) 상세(<code>-l</code>). <code>-lh</code> 사람이 읽는 크기, <code>-lt</code> 시간순, <code>-ltr</code> 오래된 순</td></tr>\n<tr><td><code>cd -</code></td><td>직전 디렉터리로 토글. <code>cd</code> 단독은 홈(<code>~</code>)으로, <code>cd ..</code> 상위</td></tr>\n<tr><td><code>tree -L 2</code></td><td>트리 구조 2단계까지 (별도 설치). <code>-d</code> 디렉터리만</td></tr>\n<tr><td><code>find . -name \"*.ts\"</code></td><td>이름으로 찾기. <code>-type f/d</code>(파일/디렉터리), <code>-mtime -7</code>(7일 내 수정)</td></tr>\n<tr><td><code>fd 패턴</code></td><td><code>find</code>의 모던 대체 — 빠르고 직관적, <code>.gitignore</code> 자동 존중. <code>fd -e ts</code>(확장자)</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">경로 기본기</span>\n<p><code>.</code>=현재 · <code>..</code>=상위 · <code>~</code>=홈 · <code>/</code>=루트 · <code>-</code>=직전(cd 한정). <strong>절대경로</strong>(<code>/Users/...</code>)는 어디서 쳐도 같은 곳, <strong>상대경로</strong>(<code>./src</code>)는 현재 위치 기준. 스크립트에선 위치에 안 흔들리게 절대경로가 안전합니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 3 ============ -->\n<section id=\"linux-ch3\">\n<div class=\"ch-head\"><span class=\"ch-code\">LX-03</span><h2>파일 보기·편집</h2></div>\n<p class=\"lede\">\"내용만 잠깐 볼 것\"과 \"고칠 것\"은 도구가 다릅니다. 큰 로그를 <code>cat</code>으로 통째로 쏟지 마세요.</p>\n<table>\n<tr><th>명령</th><th>언제 / 형태</th></tr>\n<tr><td><code>cat file</code></td><td>전체를 한 번에 출력 — <em>작은 파일</em>에만. 여러 파일 이어붙이기에도 씀</td></tr>\n<tr><td><code>less file</code></td><td>페이지 단위로 큰 파일 탐색. <code>/검색</code>, <code>G</code>(끝), <code>g</code>(처음), <code>q</code>(종료)</td></tr>\n<tr><td><code>head -n 20</code> / <code>tail -n 20</code></td><td>앞/뒤 N줄. 구조·결과 빠른 확인</td></tr>\n<tr><td><code>tail -f app.log</code></td><td><b>실시간 추적</b> — 로그가 쌓이는 걸 계속 따라감. 운영 디버깅 필수</td></tr>\n<tr><td><code>bat file</code></td><td><code>cat</code>의 모던판 — 문법 강조·줄번호·페이징 (별도 설치)</td></tr>\n<tr><td><code>vim file</code></td><td>터미널 편집기. 최소 생존: <code>i</code>(입력)→<code>Esc</code>→<code>:wq</code>(저장종료) / <code>:q!</code>(버리고 종료)</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">실전 팁</span>\n<p>에러를 쫓을 땐 <code>tail -f</code>에 필터를 얹습니다: <code>tail -f app.log | grep ERROR</code> — 새로 찍히는 에러만 실시간으로. nano가 vim보다 편하면 <code>nano</code>도 충분합니다(저장 <code>Ctrl-O</code>, 종료 <code>Ctrl-X</code>). 편집기 전쟁에 끼지 말고 <em>탈출하는 법</em>만 확실히 익히세요.</p>\n</div>\n</section>\n\n<!-- ============ CH 4 ============ -->\n<section id=\"linux-ch4\">\n<div class=\"ch-head\"><span class=\"ch-code\">LX-04</span><h2>검색 — 텍스트와 파일</h2></div>\n<p class=\"lede\">두 종류의 검색을 구분하세요 — <em>파일 안의 내용</em>을 찾는가(grep/rg), <em>파일 자체</em>를 찾는가(find/fd). 개발 일상에서 가장 자주 쓰는 무기입니다.</p>\n<table>\n<tr><th>명령</th><th>의미 / 형태</th></tr>\n<tr><td><code>grep \"패턴\" file</code></td><td>파일 안에서 줄 찾기. <code>-i</code>(대소문자 무시) <code>-n</code>(줄번호) <code>-r</code>(재귀) <code>-v</code>(반대=제외) <code>-C 3</code>(앞뒤 3줄)</td></tr>\n<tr><td><code>rg \"패턴\"</code></td><td><b>ripgrep</b> — grep의 모던 대체. 빠르고 <code>.gitignore</code> 자동 존중, 재귀가 기본. <code>rg -t ts \"useState\"</code>(타입 한정)</td></tr>\n<tr><td><code>rg -l \"패턴\"</code></td><td>매칭된 <em>파일 이름만</em> 나열 (<code>-l</code>)</td></tr>\n<tr><td><code>find . -name \"*.log\"</code></td><td>이름 패턴으로 파일 찾기</td></tr>\n<tr><td><code>fd -e log</code></td><td>확장자로 (모던, 빠름)</td></tr>\n<tr><td><code>find . -name \"*.tmp\" -delete</code></td><td>찾아서 삭제 — <b>실행 전 <code>-delete</code> 빼고 먼저 확인</b></td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">grep과 정규식</span>\n<p><code>grep</code>의 패턴은 정규식입니다 — <code>.</code>(아무 글자) <code>*</code>(0회 이상) <code>^</code>(줄 시작) <code>$</code>(줄 끝). 특수문자를 글자 그대로 찾으려면 이스케이프하거나 <code>grep -F</code>(고정 문자열). 코드베이스 탐색은 거의 항상 <code>rg</code>가 정답입니다 — 빠르고, 빌드 산출물·<code>node_modules</code>를 알아서 건너뜁니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 5 ============ -->\n<section id=\"linux-ch5\">\n<div class=\"ch-head\"><span class=\"ch-code\">LX-05</span><h2>파일 조작</h2></div>\n<p class=\"lede\">복사·이동·삭제·생성. 단순하지만 <code>rm</code>은 되돌릴 수 없으니, 파괴적 명령엔 손이 한 번 멈춰야 합니다.</p>\n<table>\n<tr><th>명령</th><th>의미 / 형태</th></tr>\n<tr><td><code>cp src dst</code></td><td>복사. 디렉터리는 <code>-r</code>(재귀). <code>-i</code> 덮어쓰기 전 확인, <code>-p</code> 속성 보존</td></tr>\n<tr><td><code>mv src dst</code></td><td>이동 <b>겸 이름 변경</b> (같은 위치로 옮기면 rename)</td></tr>\n<tr><td><code>rm file</code></td><td>삭제. <code>-r</code> 디렉터리, <code>-f</code> 강제(확인 없음), <code>-i</code> 하나씩 확인</td></tr>\n<tr><td><code>mkdir -p a/b/c</code></td><td>디렉터리 생성. <code>-p</code> 중간 경로까지 한 번에</td></tr>\n<tr><td><code>touch file</code></td><td>빈 파일 생성 / 기존 파일 수정시각 갱신</td></tr>\n<tr><td><code>ln -s 대상 링크</code></td><td>심볼릭 링크(바로가기) 생성. <code>-s</code> 없으면 하드링크</td></tr>\n</table>\n<div class=\"callout risk\">\n<span class=\"co-label\">절대 하지 말 것</span>\n<p><code>rm -rf /</code> 또는 변수 미설정 상태의 <code>rm -rf $VAR/</code>(<code>$VAR</code>이 비면 <code>rm -rf /</code>가 됨)는 시스템을 지웁니다. 안전 습관: ① <code>rm</code> 전에 같은 인자로 <code>ls</code>를 먼저 쳐서 대상을 눈으로 확인 ② 와일드카드(<code>*</code>) 삭제는 특히 조심 ③ 중요한 건 <code>rm</code> 대신 휴지통으로 보내는 도구(<code>trash</code>)를 쓰는 것도 방법.</p>\n</div>\n</section>\n\n<!-- ============ CH 6 ============ -->\n<section id=\"linux-ch6\">\n<div class=\"ch-head\"><span class=\"ch-code\">LX-06</span><h2>권한·소유권</h2></div>\n<p class=\"lede\">Unix 권한은 외울 게 아니라 <em>모델</em>입니다 — 누구(소유자/그룹/기타)가 무엇(읽기/쓰기/실행)을 할 수 있는가. <code>ls -l</code>의 맨 앞 10글자가 그 지도입니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">ls -l 의 권한 비트</span>\n<span class=\"seg\">-</span><span class=\"seg2\">rwx</span><span class=\"dim\">r-x</span>r-- &nbsp; 1 haeun staff &nbsp;...<br>\n│ └user└group└others<br>\n<span class=\"dim\">type</span> &nbsp; <span class=\"seg2\">소유자=읽기·쓰기·실행</span> <span class=\"dim\">그룹=읽기·실행</span> 기타=읽기<br>\n<br>\n<span class=\"sc-label\">숫자(8진수) 표기</span>\nr=4 &nbsp; w=2 &nbsp; x=1 &nbsp;→ &nbsp; rwx=7 &nbsp; r-x=5 &nbsp; rw-=6<br>\n<span class=\"dim\">예:</span> chmod <span class=\"seg\">755</span> = rwxr-xr-x &nbsp;|&nbsp; chmod <span class=\"seg\">644</span> = rw-r--r--\n</div>\n<table>\n<tr><th>명령</th><th>의미 / 형태</th></tr>\n<tr><td><code>chmod 755 file</code></td><td>권한을 8진수로 설정 (스크립트 실행 권한엔 보통 <code>+x</code>)</td></tr>\n<tr><td><code>chmod +x script.sh</code></td><td>실행 권한 추가 (기호 표기). <code>-x</code> 제거</td></tr>\n<tr><td><code>chown user:group file</code></td><td>소유자·그룹 변경 (보통 <code>sudo</code> 필요)</td></tr>\n<tr><td><code>umask</code></td><td>새로 만드는 파일의 기본 권한 마스크 확인/설정</td></tr>\n<tr><td><code>sudo 명령</code></td><td>관리자 권한으로 실행 — <b>무엇을 왜 올리는지 알고 쓸 것</b></td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">실전</span>\n<p>\"Permission denied\"의 90%는 두 가지입니다 — ① 스크립트에 실행 권한이 없음(<code>chmod +x</code>) ② 남의 소유 파일·시스템 경로를 건드림(<code>sudo</code> 필요하거나, 애초에 건드리면 안 됨). <code>755</code>(실행파일·디렉터리)와 <code>644</code>(일반 파일)만 손에 익혀도 일상은 충분합니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 7 ============ -->\n<section id=\"linux-ch7\">\n<div class=\"ch-head\"><span class=\"ch-code\">LX-07</span><h2>프로세스·잡</h2></div>\n<p class=\"lede\">\"포트가 이미 쓰이고 있어요\", \"멈춘 프로세스를 죽여야 해요\" — 백엔드 일상의 단골입니다. 프로세스를 보고, 신호를 보내고, 백그라운드로 다루는 법.</p>\n<table>\n<tr><th>명령</th><th>의미 / 형태</th></tr>\n<tr><td><code>ps aux | grep node</code></td><td>실행 중 프로세스에서 node 찾기 (PID 확인)</td></tr>\n<tr><td><code>top</code> / <code>htop</code></td><td>실시간 자원 모니터 (CPU·메모리). htop이 보기 편함(별도 설치)</td></tr>\n<tr><td><code>kill PID</code></td><td>프로세스에 종료 신호(<code>SIGTERM</code>) — 정상 종료 요청</td></tr>\n<tr><td><code>kill -9 PID</code></td><td><code>SIGKILL</code> — 강제 종료. <b>마지막 수단</b>(정리 못 하고 죽음)</td></tr>\n<tr><td><code>lsof -i :3000</code></td><td><b>3000 포트를 누가 쓰는지</b> 확인 → PID 찾아 kill</td></tr>\n<tr><td><code>명령 &amp;</code></td><td>백그라운드로 실행</td></tr>\n<tr><td><code>jobs</code> / <code>fg</code> / <code>bg</code></td><td>백그라운드 잡 목록 / 앞으로 / 뒤로. <code>Ctrl-Z</code>로 일시정지 후 <code>bg</code></td></tr>\n<tr><td><code>nohup 명령 &amp;</code></td><td>터미널 닫혀도 계속 실행 (장시간 작업)</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">SIGNAL — kill은 \"죽이기\"가 아니라 \"신호 보내기\"</span>\n<p><code>kill</code>은 프로세스에 신호를 보내는 명령입니다. 기본 <code>SIGTERM</code>(15)은 \"정리하고 끝내라\"는 <em>정중한 요청</em>이라 프로세스가 받아 graceful shutdown을 합니다. <code>SIGKILL</code>(9)은 OS가 즉시 죽여 거부할 수 없지만, 열린 파일·연결을 못 정리합니다. <strong>먼저 <code>kill PID</code>, 안 죽으면 <code>kill -9</code></strong> 순서가 맞습니다. <code>Ctrl-C</code>는 포그라운드 프로세스에 <code>SIGINT</code>를 보내는 것입니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 8 ============ -->\n<section id=\"linux-ch8\">\n<div class=\"ch-head\"><span class=\"ch-code\">LX-08</span><h2>파이프·텍스트 가공</h2></div>\n<p class=\"lede\">셸의 진짜 힘이 여기 있습니다. 작은 도구를 <code>|</code>로 이어 데이터를 흐르게 하면, 한 줄로 로그 분석·집계가 됩니다. \"조립\"의 영역입니다.</p>\n<table>\n<tr><th>기호</th><th>의미</th></tr>\n<tr><td><code>cmd1 | cmd2</code></td><td>cmd1의 출력을 cmd2의 입력으로 (파이프)</td></tr>\n<tr><td><code>cmd &gt; file</code></td><td>출력을 파일로 (덮어쓰기). <code>&gt;&gt;</code>는 이어쓰기</td></tr>\n<tr><td><code>cmd 2&gt; err.log</code></td><td>에러(stderr)만 파일로. <code>2&gt;&amp;1</code>은 에러를 출력에 합침</td></tr>\n<tr><td><code>cmd &gt; out 2&gt;&amp;1</code></td><td>출력과 에러를 모두 한 파일로</td></tr>\n</table>\n<table>\n<tr><th>도구</th><th>의미 / 형태</th></tr>\n<tr><td><code>wc -l</code></td><td>줄 수 세기 (<code>-w</code> 단어, <code>-c</code> 바이트)</td></tr>\n<tr><td><code>sort</code> / <code>sort -u</code></td><td>정렬 / 정렬+중복제거. <code>-n</code> 숫자, <code>-r</code> 역순</td></tr>\n<tr><td><code>uniq -c</code></td><td>연속 중복을 세기 (<b>정렬 후</b> 써야 함)</td></tr>\n<tr><td><code>cut -d',' -f1</code></td><td>구분자(<code>-d</code>)로 잘라 N번째 필드(<code>-f</code>). CSV 다루기</td></tr>\n<tr><td><code>tr 'a-z' 'A-Z'</code></td><td>문자 치환·삭제 (대문자화 등)</td></tr>\n<tr><td><code>xargs</code></td><td>앞 출력을 <em>다음 명령의 인자로</em> 변환. <code>fd -e log | xargs rm</code></td></tr>\n<tr><td><code>sed 's/old/new/g'</code></td><td>스트림 치환 (find&amp;replace). 파일 직접 수정은 <code>-i</code></td></tr>\n<tr><td><code>awk '{print $2}'</code></td><td>열 단위 가공 — 공백 구분 2번째 열 출력 등. 가벼운 표 처리</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">WORKED EXAMPLE — 접속로그에서 상위 IP 5개</span>\ncat access.log <span class=\"dim\">|</span> awk <span class=\"seg2\">'{print $1}'</span> <span class=\"dim\">|</span> sort <span class=\"dim\">|</span> uniq -c <span class=\"dim\">|</span> sort -rn <span class=\"dim\">|</span> head -5<br>\n<span class=\"dim\">└ IP 추출 → 정렬 → 개수 세기 → 많은 순 정렬 → 상위 5 — 작은 도구 5개의 조립</span>\n</div>\n<div class=\"callout warn\">\n<span class=\"co-label\">macOS 주의 — sed -i</span>\n<p>macOS(BSD)의 <code>sed -i</code>는 백업 확장자 인자를 <em>요구</em>합니다 — <code>sed -i '' 's/a/b/' file</code>(빈 따옴표 필수). GNU(Linux)는 <code>sed -i 's/a/b/' file</code>. 스크립트 이식할 때 단골 함정이라, 헷갈리면 <code>brew install gnu-sed</code>로 <code>gsed</code>를 쓰는 방법도 있습니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 9 ============ -->\n<section id=\"linux-ch9\">\n<div class=\"ch-head\"><span class=\"ch-code\">LX-09</span><h2>네트워크·HTTP</h2></div>\n<p class=\"lede\">API를 때려보고, 포트 연결을 확인하고, DNS를 추적하는 일상 도구들. 백엔드라면 <code>curl</code>은 거의 반사신경이 돼야 합니다.</p>\n<table>\n<tr><th>명령</th><th>의미 / 형태</th></tr>\n<tr><td><code>curl -i URL</code></td><td>HTTP 요청 — <code>-i</code> 응답 헤더 포함. <code>-X POST -d '{}' -H \"Content-Type: application/json\"</code></td></tr>\n<tr><td><code>curl -s URL | jq</code></td><td>조용히(<code>-s</code>) 받아 <code>jq</code>로 JSON 예쁘게/추출</td></tr>\n<tr><td><code>curl -O URL</code></td><td>파일 다운로드(원래 이름). <code>wget URL</code>도 같은 용도</td></tr>\n<tr><td><code>dig example.com</code></td><td>DNS 조회 (A 레코드·TTL). <code>+short</code> 간단히</td></tr>\n<tr><td><code>ping host</code></td><td>도달성·왕복시간 확인 (<code>Ctrl-C</code>로 종료)</td></tr>\n<tr><td><code>ss -tlnp</code> / <code>lsof -i</code></td><td>열린 포트·리스닝 소켓. macOS는 <code>lsof -i -P</code>가 흔함</td></tr>\n<tr><td><code>nc -zv host 5432</code></td><td>특정 포트 연결 가능한지 점검 (DB·서비스 도달성)</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">디버깅 순서</span>\n<p>\"서비스가 안 붙어요\"의 추적 사다리: ① <code>ping</code>으로 호스트 도달 → ② <code>nc -zv host port</code>로 포트 열림 → ③ <code>curl -v URL</code>로 HTTP 응답·TLS 핸드셰이크 → ④ <code>dig</code>로 DNS가 맞는 IP를 주는지. 위에서 아래로 한 칸씩 좁히면 어디서 끊겼는지가 드러납니다(→ 백엔드 핸드북 BE-08).</p>\n</div>\n</section>\n\n<!-- ============ CH 10 ============ -->\n<section id=\"linux-ch10\">\n<div class=\"ch-head\"><span class=\"ch-code\">LX-10</span><h2>디스크·시스템</h2></div>\n<p class=\"lede\">\"디스크가 꽉 찼어요\", \"메모리가 부족해요\"의 진단 도구들. 평소엔 안 쓰다가 사고 날 때 찾게 됩니다.</p>\n<table>\n<tr><th>명령</th><th>의미 / 형태</th></tr>\n<tr><td><code>df -h</code></td><td>디스크 여유 공간 (사람이 읽는 단위). 파티션별 사용률</td></tr>\n<tr><td><code>du -sh *</code></td><td>현재 위치 항목별 용량 합계 — <b>뭐가 용량을 먹는지</b> 추적</td></tr>\n<tr><td><code>du -sh * | sort -rh | head</code></td><td>큰 것부터 정렬해 상위만 (용량 범인 색출)</td></tr>\n<tr><td><code>free -h</code></td><td>메모리 사용량 (Linux). macOS는 <code>vm_stat</code> / <code>top</code></td></tr>\n<tr><td><code>uname -a</code></td><td>OS·커널 정보</td></tr>\n<tr><td><code>uptime</code></td><td>가동 시간·부하 평균(load average)</td></tr>\n<tr><td><code>date</code></td><td>현재 시각. 로그 타임스탬프·스크립트에서 활용</td></tr>\n</table>\n</section>\n\n<!-- ============ CH 11 ============ -->\n<section id=\"linux-ch11\">\n<div class=\"ch-head\"><span class=\"ch-code\">LX-11</span><h2>압축·아카이브</h2></div>\n<p class=\"lede\"><code>tar</code>의 플래그는 한 번 외우면 평생 씁니다 — <em>\"create / extract\"</em>의 두 패턴만 손에 넣으세요.</p>\n<table>\n<tr><th>명령</th><th>의미</th></tr>\n<tr><td><code>tar -czf out.tar.gz dir/</code></td><td><b>묶고 압축</b> — <code>c</code>reate <code>z</code>(gzip) <code>f</code>ile</td></tr>\n<tr><td><code>tar -xzf out.tar.gz</code></td><td><b>풀기</b> — e<code>x</code>tract. <code>-C 경로</code>로 풀 위치 지정</td></tr>\n<tr><td><code>tar -tzf out.tar.gz</code></td><td>풀지 않고 내용 목록만 (<code>t</code>)</td></tr>\n<tr><td><code>zip -r out.zip dir/</code></td><td>zip으로 묶기 (재귀). 윈도/공유용</td></tr>\n<tr><td><code>unzip out.zip</code></td><td>zip 풀기. <code>-d 경로</code>로 위치 지정</td></tr>\n<tr><td><code>gzip file</code> / <code>gunzip file.gz</code></td><td>단일 파일 압축/해제 (원본 대체)</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">기억법</span>\n<p><code>tar</code> = <b>T</b>ape <b>AR</b>chive. 외울 조합은 둘뿐 — 만들 땐 <code>czf</code>, 풀 땐 <code>xzf</code>. \"<b>c</b>ompress / e<b>x</b>tract, <b>z</b>ip(gzip), <b>f</b>ile\". <code>.tar.gz</code>가 가장 흔하고, 더 작게는 <code>-cJf</code>(xz)도 있습니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 12 ============ -->\n<section id=\"linux-ch12\">\n<div class=\"ch-head\"><span class=\"ch-code\">LX-12</span><h2>원격·동기화</h2></div>\n<p class=\"lede\">서버에 접속하고, 파일을 옮기고, 디렉터리를 동기화. 배포·운영의 기본 동선입니다.</p>\n<table>\n<tr><th>명령</th><th>의미 / 형태</th></tr>\n<tr><td><code>ssh user@host</code></td><td>원격 셸 접속. <code>-p 포트</code>, <code>-i key.pem</code>(키 지정)</td></tr>\n<tr><td><code>ssh user@host '명령'</code></td><td>접속 없이 원격에서 명령 한 번 실행</td></tr>\n<tr><td><code>scp file user@host:/path</code></td><td>원격으로 파일 복사. <code>-r</code> 디렉터리. 반대 방향도 가능</td></tr>\n<tr><td><code>rsync -avz src/ host:dst/</code></td><td><b>변경분만</b> 동기화 — 빠르고 재개 가능. <code>-a</code> 보존 <code>-v</code> 로그 <code>-z</code> 압축</td></tr>\n<tr><td><code>rsync -avzn ...</code></td><td><code>-n</code>(dry-run) — <b>실제로 옮기기 전 무엇이 바뀔지 미리보기</b></td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">rsync의 끝 슬래시 함정</span>\n<p><code>rsync src/ dst/</code>(끝 <code>/</code>)는 <em>src 안의 내용</em>을 dst로, <code>rsync src dst/</code>(끝 <code>/</code> 없음)는 <em>src 디렉터리째</em> dst 안으로 — 결과가 다릅니다. 큰 동기화는 항상 <code>-n</code>(dry-run)으로 먼저 확인하는 습관이 사고를 막습니다. SSH 키는 <code>~/.ssh/config</code>에 호스트 별칭을 등록해두면 <code>ssh myserver</code>로 짧게 씁니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 13 ============ -->\n<section id=\"linux-ch13\">\n<div class=\"ch-head\"><span class=\"ch-code\">LX-13</span><h2>셸 환경·생산성</h2></div>\n<p class=\"lede\">같은 명령을 매번 길게 치지 마세요. 환경변수·alias·히스토리·키바인딩이 손의 속도를 바꿉니다. 네 도구 체인(zsh·mise·chezmoi) 기준으로.</p>\n<h3><span class=\"h3-tag\">13.1</span>환경·변수·히스토리</h3>\n<table>\n<tr><th>명령</th><th>의미</th></tr>\n<tr><td><code>export VAR=value</code></td><td>환경변수 설정 (자식 프로세스에 전달). <code>echo $VAR</code>로 확인</td></tr>\n<tr><td><code>env</code> / <code>printenv</code></td><td>현재 환경변수 목록</td></tr>\n<tr><td><code>alias gs='git status'</code></td><td>긴 명령에 별칭. <code>~/.zshrc</code>에 넣어 영구화</td></tr>\n<tr><td><code>history</code> / <code>Ctrl-R</code></td><td>이전 명령 / <b>역방향 검색</b>(치다가 Ctrl-R, 같은 거 다시 누르면 이전 매치)</td></tr>\n<tr><td><code>!!</code> / <code>!$</code></td><td>직전 명령 전체 / 직전 명령의 마지막 인자 (<code>sudo !!</code> 단골)</td></tr>\n<tr><td><code>cmd1 &amp;&amp; cmd2</code> / <code>cmd1 || cmd2</code></td><td>앞이 성공하면(&amp;&amp;) / 실패하면(||) 다음 실행</td></tr>\n</table>\n<h3><span class=\"h3-tag\">13.2</span>네 도구 체인</h3>\n<table>\n<tr><th>도구</th><th>역할 / 자주 쓰는 형태</th></tr>\n<tr><td><code>mise</code></td><td>언어 런타임 관리 — <code>mise use node@22</code>(프로젝트별 버전), <code>mise install</code>, <code>mise ls</code>. <code>.mise.toml</code>로 프로젝트 고정</td></tr>\n<tr><td><code>brew</code></td><td>macOS 패키지 — <code>brew install rg fd bat jq</code>, <code>brew update &amp;&amp; brew upgrade</code>, <code>brew list</code></td></tr>\n<tr><td><code>chezmoi</code></td><td>dotfiles 관리 — <code>chezmoi edit ~/.zshrc</code>, <code>chezmoi apply</code>(반영), <code>chezmoi diff</code>(변경 미리보기)</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">.zshrc는 chezmoi로 관리</span>\n<p>alias·환경변수·PATH를 <code>~/.zshrc</code>에 직접 고치면 chezmoi 관리와 어긋날 수 있습니다 — <code>chezmoi edit ~/.zshrc</code>로 고치고 <code>chezmoi apply</code>로 반영하세요. 새 alias를 추가했으면 <code>source ~/.zshrc</code>(또는 새 탭)로 현재 셸에 로드. mise는 <code>.zshrc</code>에 <code>eval \"$(mise activate zsh)\"</code>가 있어야 자동 전환됩니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 14 ============ -->\n<section id=\"linux-ch14\">\n<div class=\"ch-head\"><span class=\"ch-code\">LX-14</span><h2>치트시트 — 자주 쓰는 한 줄</h2></div>\n<p class=\"lede\">실전에서 반복되는 조합들. 외우기보다 \"이런 게 가능하다\"를 알아두고 필요할 때 찾으세요.</p>\n<div class=\"glossary\">\n<div class=\"g-row\"><div class=\"g-term\"><b>포트 점유 죽이기</b><span>kill by port</span></div><div class=\"g-def\"><code>lsof -i :3000</code> 로 PID 확인 → <code>kill -9 &lt;PID&gt;</code>. 또는 한 줄: <code>lsof -ti :3000 | xargs kill -9</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>로그 실시간 + 필터</b><span>tail + grep</span></div><div class=\"g-def\"><code>tail -f app.log | grep -i error</code> — 새로 찍히는 에러만 실시간으로</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>용량 범인 찾기</b><span>biggest dirs</span></div><div class=\"g-def\"><code>du -sh * | sort -rh | head</code> — 현재 위치에서 용량 큰 것 상위</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>코드 전체 검색</b><span>ripgrep</span></div><div class=\"g-def\"><code>rg -n \"TODO\" -t ts</code> — 타입스크립트에서 TODO를 줄번호와 함께</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>특정 파일 일괄 삭제</b><span>fd + xargs</span></div><div class=\"g-def\"><code>fd -e tmp | xargs rm</code> — 먼저 <code>fd -e tmp</code>만 쳐서 대상 확인 후</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>JSON API 찔러보기</b><span>curl + jq</span></div><div class=\"g-def\"><code>curl -s localhost:8080/api/users | jq '.[].name'</code> — 받아서 이름만 추출</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>중복 제거 카운트</b><span>sort | uniq -c</span></div><div class=\"g-def\"><code>... | sort | uniq -c | sort -rn</code> — 빈도 집계의 정석 (반드시 sort 먼저)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>방금 명령 sudo로</b><span>!!</span></div><div class=\"g-def\"><code>sudo !!</code> — \"Permission denied\" 뜬 직후 가장 빠른 재실행</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>동기화 미리보기</b><span>rsync -n</span></div><div class=\"g-def\"><code>rsync -avzn src/ host:dst/</code> — 실제 전송 전 무엇이 바뀔지 dry-run</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>출력+에러 한 파일로</b><span>2&gt;&amp;1</span></div><div class=\"g-def\"><code>./build.sh &gt; build.log 2&gt;&amp;1</code> — 정상·에러 모두 로그로</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>히스토리 검색</b><span>Ctrl-R</span></div><div class=\"g-def\">치다가 <code>Ctrl-R</code> → 키워드 입력 → 같은 키 반복으로 이전 매치. 긴 명령 재사용의 핵심</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>안전한 삭제 습관</b><span>ls before rm</span></div><div class=\"g-def\"><code>rm</code> 전에 같은 인자로 <code>ls</code>를 먼저 — 와일드카드가 무엇을 잡는지 눈으로 확인</div></div>\n</div>\n<div class=\"callout gm\">\n<span class=\"co-label\">학습 순서 제안</span>\n<p>전부 외우려 하지 마세요. 손에 먼저 붙일 것: <code>ls -la</code> · <code>cd -</code> · <code>rg</code> · <code>tail -f</code> · <code>lsof -i :포트</code> · <code>kill</code> · <code>curl | jq</code> · <code>Ctrl-R</code>. 이 여덟 개가 일상의 80%입니다. 파이프(<code>|</code>)와 종료코드(<code>&amp;&amp;</code>/<code>||</code>) 사고만 잡히면 나머지는 필요할 때 이 핸드북에서 찾으면 됩니다(→ 백엔드 핸드북과 함께 보면 BE-08 네트워킹·BE-09 관측가능성의 실습 도구가 됩니다).</p>\n</div>\n</section>\n\n<footer>\nLINUX / SHELL COMMANDS HANDBOOK · V1 · 2026-06<br>\nENV : macOS(Darwin) · zsh · mise · chezmoi · MODERN CLI(ripgrep·fd·bat·jq)<br>\nNOTE : BSD vs GNU 차이 있는 항목은 본문 표기 · COMPANION : BACKEND ENGINEERING HANDBOOK\n</footer>\n\n<section id=\"doc-vi\">\n<div class=\"ch-head\"><span class=\"ch-code\">SOURCE</span><h2>vi</h2></div>\n</section>\n\n<header class=\"hero\">\n  <div class=\"hero-serial\">\n    <span>DOC : VI-HANDBOOK-V1</span>\n    <span>TOOL : vi / Vim (macOS 기본 vim) · vimtutor</span>\n    <span>LANG : KO</span>\n  </div>\n  <h1>vi / Vim 단축키<br>핸드북</h1>\n  <p class=\"hero-sub\">vi는 단축키 <em>목록</em>이 아니라 <strong>언어</strong>다 — 모드 위에서 \"연산자 × 모션\"을 조합한다. 이 문법 하나를 잡으면 외울 게 덧셈이 아니라 곱셈으로 줄어든다. <code>d</code>(삭제)와 <code>w</code>(단어)·<code>i\"</code>(따옴표 안)를 알면 <code>dw</code>·<code>di\"</code>가 공짜로 나온다. macOS 기본 vim 기준.</p>\n  <div class=\"hero-meta\">START : 터미널에서 <code>vimtutor</code> (30분, 한국어 <code>vimtutor ko</code>) — 이 문서는 그 다음의 빠른 참조<br>COMPILED : 2026-06</div>\n</header>\n\n<!-- ============ CH 1 ============ -->\n<section id=\"vi-ch1\">\n<div class=\"ch-head\"><span class=\"ch-code\">VI-01</span><h2>사고 모델 — 모드와 문법</h2></div>\n<p class=\"lede\">vi를 어렵게 만드는 건 단축키 개수가 아니라 두 가지 개념이다 — (1) <strong>모드</strong>, (2) <strong>\"동사(연산자) + 명사(모션/객체)\" 문법</strong>. 이 둘을 잡으면 나머지는 조합이다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">THE GRAMMAR — 명령은 문장이다</span>\n[ <span class=\"seg2\">횟수</span> ] <span class=\"seg\">연산자</span> [ <span class=\"seg2\">횟수</span> ] <span class=\"seg2\">모션/객체</span><br>\n<span class=\"dim\">예:</span> <span class=\"seg\">d</span><span class=\"seg2\">w</span> = 단어 삭제 &nbsp;|&nbsp; <span class=\"seg2\">2</span><span class=\"seg\">d</span><span class=\"seg2\">w</span> = 두 단어 삭제 &nbsp;|&nbsp; <span class=\"seg\">c</span><span class=\"seg2\">i\"</span> = 따옴표 안 바꾸기<br>\n<span class=\"dim\">└ 연산자 d·c·y 한 줌 × 모션·객체 한 줌 = 수백 개 명령이 곱셈으로 생성된다</span>\n</div>\n<p>핵심 통찰: <strong>vi의 명령은 영어 문장처럼 읽힌다.</strong> <code>d</code>(delete) + <code>w</code>(word) = \"단어를 지워라\". <code>c</code>(change) + <code>i\"</code>(inner quotes) = \"따옴표 안을 바꿔라\". 그래서 새 명령을 외우는 게 아니라 <em>아는 동사와 명사를 새로 조합</em>한다. <code>y</code>(복사)를 배우는 순간 <code>yw</code>·<code>yi(</code>·<code>y$</code>를 따로 안 배워도 쓸 수 있는 이유다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">CORE INSIGHT</span>\n<p>외울 것은 결국 세 묶음뿐이다 — <strong>① 연산자</strong>(<code>d</code> 삭제 · <code>c</code> 바꾸기 · <code>y</code> 복사), <strong>② 모션</strong>(어디로/어디까지: <code>w</code> <code>$</code> <code>}</code> <code>G</code>…), <strong>③ 텍스트 객체</strong>(무엇을: <code>iw</code> <code>i\"</code> <code>i(</code>…). 이 셋의 곱이 vi 편집의 전부다. 단축키를 \"암기\"하려 들면 끝이 없고, \"문법\"으로 보면 유한하다.</p>\n</div>\n</section>\n\n<!-- ============ CH 2 ============ -->\n<section id=\"vi-ch2\">\n<div class=\"ch-head\"><span class=\"ch-code\">VI-02</span><h2>모드와 전환</h2></div>\n<p class=\"lede\">vi가 다른 에디터와 다른 단 하나의 이유 — 키가 모드마다 다른 뜻을 갖는다. Normal에서 <code>d</code>는 \"삭제 명령\"이고, Insert에서 <code>d</code>는 글자 'd'다.</p>\n<table>\n<tr><th>모드</th><th>역할</th><th>진입</th></tr>\n<tr><td><b>Normal</b> (기본·집)</td><td>이동·명령. vi의 본진 — 대부분 시간을 여기서</td><td><code>Esc</code> (또는 <code>Ctrl-[</code>)</td></tr>\n<tr><td><b>Insert</b></td><td>실제 글자 입력</td><td><code>i a o</code> 등 (아래)</td></tr>\n<tr><td><b>Visual</b></td><td>영역 선택 후 연산</td><td><code>v</code> <code>V</code> <code>Ctrl-v</code></td></tr>\n<tr><td><b>Command-line</b></td><td>저장·종료·치환 등 ex 명령</td><td><code>:</code> (그리고 <code>/</code> <code>?</code> 검색)</td></tr>\n</table>\n<table>\n<tr><th>Insert 진입</th><th>의미</th></tr>\n<tr><td><code>i</code> / <code>a</code></td><td>커서 <b>앞</b> / <b>뒤</b>에서 입력 (insert / append)</td></tr>\n<tr><td><code>I</code> / <code>A</code></td><td>줄 <b>맨 앞(첫 글자)</b> / <b>맨 끝</b>에서 입력</td></tr>\n<tr><td><code>o</code> / <code>O</code></td><td><b>아래 / 위</b>에 새 줄 열고 입력</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">길 잃으면 Esc</span>\n<p>어디 있는지 모르겠으면 무조건 <code>Esc</code>를 두어 번 — Normal로 돌아온다. <strong>Normal이 집이다.</strong> 초보가 헤매는 90%는 \"지금 무슨 모드인지\" 감각이 없어서다. 입력이 끝나면 습관적으로 <code>Esc</code>로 빠져나오는 리듬을 들이면 vi가 갑자기 쉬워진다.</p>\n</div>\n</section>\n\n<!-- ============ CH 3 ============ -->\n<section id=\"vi-ch3\">\n<div class=\"ch-head\"><span class=\"ch-code\">VI-03</span><h2>이동 (모션)</h2></div>\n<p class=\"lede\">모션은 그 자체로 \"이동\"이면서, 연산자 뒤에 붙으면 \"어디까지 적용할지\"가 된다 — <code>w</code>는 \"다음 단어로 이동\"이자 <code>dw</code>의 \"단어만큼\"이다. 그래서 모션을 익히면 편집까지 같이 빨라진다.</p>\n<table>\n<tr><th>모션</th><th>이동</th></tr>\n<tr><td><code>h j k l</code></td><td>좌 · 하 · 상 · 우 (방향키 대신 — 손이 홈 위치에 머문다)</td></tr>\n<tr><td><code>w</code> / <code>b</code> / <code>e</code></td><td>다음 단어 앞 / 이전 단어 앞 / 단어 끝. 대문자 <code>W B E</code>는 공백 기준(구두점 무시)</td></tr>\n<tr><td><code>0</code> / <code>^</code> / <code>$</code></td><td>줄 맨 앞(0칸) / 첫 글자(공백 제외) / 줄 끝</td></tr>\n<tr><td><code>gg</code> / <code>G</code></td><td>파일 처음 / 파일 끝. <code>42G</code> 또는 <code>:42</code> = 42번째 줄로</td></tr>\n<tr><td><code>{</code> / <code>}</code></td><td>이전 / 다음 문단(빈 줄 기준)</td></tr>\n<tr><td><code>f{x}</code> / <code>t{x}</code></td><td>줄에서 글자 x <b>까지(위)</b> / x <b>직전까지</b>. <code>F T</code>는 역방향. <code>;</code> 반복 · <code>,</code> 역반복</td></tr>\n<tr><td><code>%</code></td><td>짝 괄호로 점프 ( <code>( ) { } [ ]</code> )</td></tr>\n<tr><td><code>Ctrl-d</code> / <code>Ctrl-u</code></td><td>반 페이지 아래 / 위. <code>Ctrl-f</code> / <code>Ctrl-b</code>는 한 페이지</td></tr>\n<tr><td><code>H</code> / <code>M</code> / <code>L</code></td><td>화면 맨 위 / 가운데 / 맨 아래 줄로. <code>zz</code> 현재 줄을 화면 중앙에</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">실전</span>\n<p><code>f</code>는 한 줄 안 이동의 핵심이다 — \"이 줄의 다음 쉼표로\" = <code>f,</code>, 그 직전까지 지우기 = <code>dt,</code>(till comma). 마우스로 클릭하던 걸 <code>f{글자}</code> 한 번으로 대체하는 게 vi 속도의 절반이다.</p>\n</div>\n</section>\n\n<!-- ============ CH 4 ============ -->\n<section id=\"vi-ch4\">\n<div class=\"ch-head\"><span class=\"ch-code\">VI-04</span><h2>편집 — 연산자</h2></div>\n<p class=\"lede\">연산자는 \"무엇을 할지\"(동사)다. 뒤에 모션(VI-03)이나 텍스트 객체(VI-05)를 붙여 범위를 정한다. 연산자를 두 번 치면(<code>dd</code> <code>cc</code> <code>yy</code>) \"현재 줄 전체\"가 된다.</p>\n<table>\n<tr><th>연산자</th><th>의미 / 조합 예</th></tr>\n<tr><td><code>d</code></td><td>삭제(잘라내기). <code>dw</code> 단어 · <code>d$</code> 줄 끝까지 · <code>dG</code> 파일 끝까지 · <code>dd</code> 한 줄</td></tr>\n<tr><td><code>c</code></td><td>바꾸기(삭제+Insert 진입). <code>cw</code> 단어 · <code>cc</code> 줄 전체 · <code>c$</code> 줄 끝까지</td></tr>\n<tr><td><code>y</code></td><td>복사(yank). <code>yw</code> · <code>yy</code> 한 줄 · <code>y$</code> 줄 끝까지</td></tr>\n<tr><td><code>p</code> / <code>P</code></td><td>붙여넣기 — 커서 <b>뒤</b> / <b>앞</b>. 줄 단위 복사(<code>yy</code>)면 아래 줄/위 줄에</td></tr>\n</table>\n<table>\n<tr><th>빠른 편집 (단일 키)</th><th>의미</th></tr>\n<tr><td><code>x</code> / <code>X</code></td><td>커서 글자 삭제 / 앞 글자 삭제</td></tr>\n<tr><td><code>r{x}</code> / <code>R</code></td><td>한 글자만 x로 교체 / 덮어쓰기(Replace) 모드</td></tr>\n<tr><td><code>s</code> / <code>S</code></td><td>글자 지우고 입력 / 줄 비우고 입력 (= <code>cc</code>)</td></tr>\n<tr><td><code>~</code> / <code>J</code></td><td>대소문자 토글 / 아래 줄을 현재 줄에 합치기</td></tr>\n<tr><td><code>&gt;&gt;</code> / <code>&lt;&lt;</code></td><td>줄 들여쓰기 / 내어쓰기</td></tr>\n<tr><td><code>u</code> / <code>Ctrl-r</code> / <code>.</code></td><td>실행취소 / 다시실행 / <b>직전 변경 반복</b>(VI-09)</td></tr>\n</table>\n</section>\n\n<!-- ============ CH 5 ============ -->\n<section id=\"vi-ch5\">\n<div class=\"ch-head\"><span class=\"ch-code\">VI-05</span><h2>텍스트 객체 — vi의 진짜 힘</h2></div>\n<p class=\"lede\">모션이 \"어디까지\"라면, 텍스트 객체는 \"무엇을\"이다 — 커서가 그 안 <em>어디에 있든</em> 단어·따옴표·괄호 단위를 통째로 잡는다. 위치를 정렬할 필요가 없어서 압도적으로 빠르다.</p>\n<table>\n<tr><th>객체</th><th>의미 (i=inner 안쪽 / a=around 경계 포함)</th></tr>\n<tr><td><code>iw</code> / <code>aw</code></td><td>단어 / 단어+주변 공백</td></tr>\n<tr><td><code>i\"</code> <code>i'</code> <code>i`</code></td><td>따옴표 <b>안</b> 내용 (<code>a\"</code>는 따옴표까지)</td></tr>\n<tr><td><code>i(</code> <code>i{</code> <code>i[</code> <code>i&lt;</code></td><td>괄호 <b>안</b> (<code>ib</code>=<code>i(</code>, <code>iB</code>=<code>i{</code>). <code>a(</code>는 괄호까지</td></tr>\n<tr><td><code>it</code> / <code>at</code></td><td>HTML/XML 태그 안 / 태그 포함</td></tr>\n<tr><td><code>ip</code> / <code>ap</code></td><td>문단 / 문단+빈 줄</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">연산자 × 텍스트 객체 — 실전 조합</span>\n<span class=\"seg\">c</span><span class=\"seg2\">i\"</span>  따옴표 안 내용 바꾸기 &nbsp; <span class=\"dim\">\"old\"  →  커서 아무 데나 → \"▮\"</span><br>\n<span class=\"seg\">d</span><span class=\"seg2\">i(</span>  괄호 안 통째로 삭제 &nbsp;&nbsp;&nbsp; <span class=\"dim\">foo(  a, b  )  →  foo()</span><br>\n<span class=\"seg\">y</span><span class=\"seg2\">ip</span>  문단 복사 &nbsp;&nbsp; <span class=\"seg\">d</span><span class=\"seg2\">it</span>  태그 안 비우기 &nbsp;&nbsp; <span class=\"seg\">c</span><span class=\"seg2\">aw</span>  단어+공백 교체\n</div>\n<div class=\"callout\">\n<span class=\"co-label\">왜 강력한가</span>\n<p><code>ci\"</code> 하나로 끝나는 작업을 떠올려 보라 — 따옴표 안 어디에 커서가 있든, 시작/끝으로 이동할 필요 없이 내용이 통째로 비워지고 입력 모드로 들어간다. 함수 인자 바꾸기 <code>ci(</code>, JSX 태그 내용 바꾸기 <code>cit</code>, 변수명 바꾸기 <code>ciw</code> — 코드 편집의 대부분이 이 패턴 몇 개로 수렴한다. <em>\"안(i)이냐 경계 포함(a)이냐\"</em>만 구분하면 된다.</p>\n</div>\n</section>\n\n<!-- ============ CH 6 ============ -->\n<section id=\"vi-ch6\">\n<div class=\"ch-head\"><span class=\"ch-code\">VI-06</span><h2>검색·치환</h2></div>\n<p class=\"lede\">검색은 가장 빠른 이동 수단이기도 하다(원하는 단어로 점프). 치환은 ex 명령(<code>:</code>)의 영역으로, 범위 지정이 핵심이다.</p>\n<table>\n<tr><th>검색</th><th>의미</th></tr>\n<tr><td><code>/패턴</code> / <code>?패턴</code></td><td>아래로 / 위로 검색 (Enter). <code>n</code> 다음 · <code>N</code> 이전(반대 방향)</td></tr>\n<tr><td><code>*</code> / <code>#</code></td><td>커서 아래 <b>단어</b>를 아래로 / 위로 검색 (변수 추적에 유용)</td></tr>\n<tr><td><code>:noh</code></td><td>검색 강조 끄기 (<code>nohlsearch</code>)</td></tr>\n</table>\n<table>\n<tr><th>치환 (:s)</th><th>의미</th></tr>\n<tr><td><code>:s/old/new/</code></td><td>현재 줄의 <b>첫</b> old를 new로</td></tr>\n<tr><td><code>:s/old/new/g</code></td><td>현재 줄의 <b>모든</b> old (g = global, 줄 내 전체)</td></tr>\n<tr><td><code>:%s/old/new/g</code></td><td><b>파일 전체</b>의 모든 old (%=전체 범위)</td></tr>\n<tr><td><code>:%s/old/new/gc</code></td><td>전체 치환하되 <b>하나씩 확인</b>(c = confirm: y/n/a/q)</td></tr>\n<tr><td><code>:10,20s/old/new/g</code></td><td>10~20번째 줄만. 비주얼 선택 후 <code>:s</code>는 <code>:'&lt;,'&gt;</code> 범위로</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">특수문자</span>\n<p>치환 패턴은 정규식이라 <code>. * / \\ &amp;</code> 등은 특별한 뜻을 갖는다 — 슬래시를 찾으려면 <code>\\/</code>로 이스케이프하거나, 구분자를 바꿔 <code>:%s#old/path#new/path#g</code>처럼 <code>#</code>를 써도 된다(가독성↑).</p>\n</div>\n</section>\n\n<!-- ============ CH 7 ============ -->\n<section id=\"vi-ch7\">\n<div class=\"ch-head\"><span class=\"ch-code\">VI-07</span><h2>비주얼 모드</h2></div>\n<p class=\"lede\">\"먼저 선택하고, 그다음 무엇을 할지 정한다\" — 연산자+모션의 순서를 뒤집은 모드. 범위가 눈에 보여서 직관적이고, 한 영역에 여러 작업을 시도할 때 좋다.</p>\n<table>\n<tr><th>진입 / 동작</th><th>의미</th></tr>\n<tr><td><code>v</code> / <code>V</code> / <code>Ctrl-v</code></td><td>문자 단위 / <b>줄 단위</b> / <b>블록(열) 단위</b> 선택</td></tr>\n<tr><td>선택 후 <code>d</code> <code>y</code> <code>c</code></td><td>삭제 / 복사 / 바꾸기. <code>&gt;</code> <code>&lt;</code> 들여쓰기, <code>~</code> 대소문자</td></tr>\n<tr><td><code>gv</code></td><td>직전 선택 영역 다시 선택</td></tr>\n<tr><td>블록(<code>Ctrl-v</code>) + <code>I</code>/<code>A</code></td><td>여러 줄 <b>맨 앞/뒤에 동시 입력</b> (Esc로 전 줄에 반영) — 주석 일괄 추가에</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">언제 비주얼, 언제 연산자</span>\n<p>범위가 명확하면(단어·따옴표·줄 수) <code>ci\"</code> <code>3dd</code>처럼 <strong>연산자+모션</strong>이 빠르다 — 손이 덜 움직이고 <code>.</code>로 반복 가능. 범위가 애매하거나 눈으로 확인하며 늘리고 싶으면 <strong>비주얼</strong>이 편하다. 블록 비주얼(<code>Ctrl-v</code>)은 다른 에디터의 \"멀티 커서\" 자리를 메운다.</p>\n</div>\n</section>\n\n<!-- ============ CH 8 ============ -->\n<section id=\"vi-ch8\">\n<div class=\"ch-head\"><span class=\"ch-code\">VI-08</span><h2>파일·창·저장·종료</h2></div>\n<p class=\"lede\">\"vi에서 못 빠져나온다\"는 농담의 답이 여기 있다 — 전부 <code>:</code>(command-line)에서 한다. <code>Esc</code>로 Normal에 온 뒤 <code>:</code>를 쳐라.</p>\n<table>\n<tr><th>저장·종료</th><th>의미</th></tr>\n<tr><td><code>:w</code></td><td>저장(write). <code>:w 파일명</code> 다른 이름으로</td></tr>\n<tr><td><code>:q</code> / <code>:q!</code></td><td>종료 / <b>저장 안 하고</b> 강제 종료(버림)</td></tr>\n<tr><td><code>:wq</code> / <code>:x</code> / <code>ZZ</code></td><td>저장하고 종료 (셋 다 같음. <code>ZZ</code>는 Normal에서 바로)</td></tr>\n<tr><td><code>:wa</code> / <code>:qa</code></td><td>모든 창 저장 / 모두 종료 (<code>:wqa</code> 저장+모두 종료)</td></tr>\n</table>\n<table>\n<tr><th>여러 파일·창·탭</th><th>의미</th></tr>\n<tr><td><code>:e 파일</code></td><td>파일 열기(edit)</td></tr>\n<tr><td><code>:ls</code> · <code>:bn</code> · <code>:bp</code> · <code>:b이름</code></td><td>버퍼 목록 · 다음 · 이전 · 이름으로 이동</td></tr>\n<tr><td><code>:sp</code> / <code>:vsp</code></td><td>가로 분할 / 세로 분할 창</td></tr>\n<tr><td><code>Ctrl-w</code> 다음 <code>h j k l</code></td><td>창 사이 이동. <code>Ctrl-w w</code> 순환</td></tr>\n<tr><td><code>:tabnew</code> · <code>gt</code> / <code>gT</code></td><td>새 탭 · 다음 탭 / 이전 탭</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">\"못 나가요\"의 해답</span>\n<p>지금 입력 중이라 명령이 안 먹으면 → <code>Esc</code> 먼저. 그다음: 저장하고 나가기 <code>:wq</code>, <strong>버리고 나가기 <code>:q!</code></strong>. 변경 안 했으면 <code>:q</code>. 이 세 개면 평생 탈출 가능하다.</p>\n</div>\n</section>\n\n<!-- ============ CH 9 ============ -->\n<section id=\"vi-ch9\">\n<div class=\"ch-head\"><span class=\"ch-code\">VI-09</span><h2>생산성 + 치트시트</h2></div>\n<p class=\"lede\">vi가 \"빠른 에디터\"를 넘어 \"증폭기\"가 되는 지점 — 반복(<code>.</code>)과 매크로다. 한 번 잘 만든 변경을 공짜로 N번 재생한다.</p>\n<table>\n<tr><th>증폭 도구</th><th>의미</th></tr>\n<tr><td><code>.</code> (닷)</td><td><b>직전 변경을 반복</b>. <code>ciwfoo&lt;Esc&gt;</code> 후 다음 단어에서 <code>.</code> — vi 생산성의 핵심</td></tr>\n<tr><td><code>{n}{명령}</code></td><td>횟수 곱하기 — <code>3dd</code> 세 줄 삭제 · <code>5j</code> 다섯 줄 아래 · <code>2&gt;&gt;</code> 두 줄 들여쓰기</td></tr>\n<tr><td><code>q{a}</code> … <code>q</code> / <code>@a</code> / <code>@@</code></td><td>레지스터 a에 매크로 <b>녹화</b> / <b>재생</b> / 직전 매크로 반복. <code>10@a</code> 10번</td></tr>\n<tr><td><code>m{a}</code> / <code>` a</code></td><td>마크 a 찍기 / 마크 a로 점프 (<code>``</code> 직전 위치로)</td></tr>\n<tr><td><code>\"+y</code> / <code>\"+p</code></td><td>시스템 클립보드로 복사 / 에서 붙여넣기 (클립보드 지원 vim)</td></tr>\n</table>\n<p>치트시트 — 손에 먼저 붙일 조합:</p>\n<div class=\"glossary\">\n<div class=\"g-row\"><div class=\"g-term\"><b>줄 복제</b><span>yyp</span></div><div class=\"g-def\"><code>yy</code>(줄 복사) → <code>p</code>(아래 붙이기). 한 줄 통째 복제.</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>단어 바꾸기</b><span>ciw</span></div><div class=\"g-def\">커서가 단어 어디 있든 그 단어를 비우고 입력. 다음 단어에서 <code>.</code>로 반복.</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>따옴표/괄호 안 교체</b><span>ci\" · ci(</span></div><div class=\"g-def\">문자열·인자 내용 통째 교체. 위치 정렬 불필요.</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>줄 끝까지 지우기</b><span>D (= d$)</span></div><div class=\"g-def\">커서부터 줄 끝까지 삭제. <code>C</code>는 같은 범위 바꾸기(<code>c$</code>).</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>줄 맨 끝에서 입력</b><span>A</span></div><div class=\"g-def\">어디 있든 줄 끝으로 가 입력. <code>I</code>는 줄 첫 글자에서 입력.</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>아래에 새 줄</b><span>o / O</span></div><div class=\"g-def\">아래(<code>o</code>)·위(<code>O</code>)에 빈 줄 열고 바로 입력.</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>전체 치환</b><span>:%s/a/b/g</span></div><div class=\"g-def\">파일 전체 a→b. 확인하며 하려면 <code>/gc</code>.</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>들여쓰기 일괄</b><span>Vjj&gt; </span></div><div class=\"g-def\">비주얼 줄 선택(<code>V</code>) 후 범위 늘리고 <code>&gt;</code>. 반복은 <code>.</code>.</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>방금 한 거 또</b><span>. (닷)</span></div><div class=\"g-def\">직전 변경 반복. \"수정 → <code>n</code>으로 다음 → <code>.</code>\" 리듬이 핵심.</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>되돌리기</b><span>u / Ctrl-r</span></div><div class=\"g-def\">실행취소 / 다시실행. 마음껏 실험하고 되돌려라.</div></div>\n</div>\n<div class=\"callout gm\">\n<span class=\"co-label\">학습 순서 제안</span>\n<p>한 번에 다 외우지 마라. ① <code>vimtutor</code> 30분으로 모드·기본 이동 → ② <code>i a o</code> / <code>Esc</code> / <code>:wq</code> <code>:q!</code>로 생존 → ③ <code>dd yy p</code> <code>x</code> <code>u</code>로 일상 편집 → ④ <code>ciw</code> <code>ci\"</code> <code>ci(</code> 텍스트 객체(여기서 속도가 폭발) → ⑤ <code>/검색</code> <code>:%s</code> <code>.</code> 반복 → ⑥ 매크로. 4단계까지만 가도 대부분의 편집이 빨라진다. (셸 작업은 → 리눅스/셸 핸드북과 함께.)</p>\n</div>\n</section>\n\n<footer>\nvi / VIM SHORTCUTS HANDBOOK · V1 · 2026-06<br>\nMODEL : MODES + OPERATOR×MOTION GRAMMAR · START : vimtutor (ko)<br>\nCOMPANION : LINUX / SHELL COMMANDS HANDBOOK · BACKEND ENGINEERING HANDBOOK\n</footer>\n\n<section id=\"doc-docker\">\n<div class=\"ch-head\"><span class=\"ch-code\">SOURCE</span><h2>Docker 예시</h2></div>\n</section>\n\n<header class=\"hero\">\n  <div class=\"hero-serial\">\n    <span>DOC : DOCKER-EXAMPLES-V1</span>\n    <span>STACK : SPRING BOOT · POSTGRES · REDIS · NGINX</span>\n    <span>LANG : KO</span>\n  </div>\n  <h1>Docker<br>예시 사례</h1>\n  <p class=\"hero-sub\">이 스택을 한 번에 띄우는 실전 Dockerfile·compose 레시피. 개념은 Docker·배포 핸드북에. 여기서는 <strong>바로 복사해 쓰는 설정</strong>만 — 멀티스테이지 빌드, compose 한 파일, 볼륨·네트워크·헬스체크까지 실재 문법으로.</p>\n  <div class=\"hero-meta\">NOTE : 버전 태그는 예시 — 실제 프로젝트의 JDK·이미지 버전에 맞춰 고정할 것<br>COMPILED : 2026-06</div>\n</header>\n\n<!-- ============ CH 1 ============ -->\n<section id=\"docker-ch1\">\n<div class=\"ch-head\"><span class=\"ch-code\">DOCKER-01</span><h2>Spring Boot Dockerfile</h2></div>\n<p class=\"lede\">언제·왜: jar 하나를 이미지로 굽는 가장 표준적인 방법. <em>멀티스테이지</em>로 빌드 도구(Gradle·JDK)는 빌드 스테이지에만 두고, 런타임 이미지엔 JRE와 jar만 남깁니다. 이미지가 수백 MB 작아지고 공격 표면도 줄어듭니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">Dockerfile — 멀티스테이지 (build → runtime)</span>\n<span class=\"seg\"># ---- build stage ----</span><br>\n<span class=\"seg2\">FROM</span> gradle:8.7-jdk21 <span class=\"seg2\">AS</span> build<br>\n<span class=\"seg2\">WORKDIR</span> /app<br>\n<span class=\"dim\"># 의존성 먼저 복사 → 레이어 캐시 (DOCKER-02 참조)</span><br>\n<span class=\"seg2\">COPY</span> build.gradle settings.gradle ./<br>\n<span class=\"seg2\">COPY</span> gradle ./gradle<br>\n<span class=\"seg2\">RUN</span> gradle dependencies --no-daemon || true<br>\n<span class=\"seg2\">COPY</span> src ./src<br>\n<span class=\"seg2\">RUN</span> gradle bootJar --no-daemon<br>\n<br>\n<span class=\"seg\"># ---- runtime stage ----</span><br>\n<span class=\"seg2\">FROM</span> eclipse-temurin:21-jre<br>\n<span class=\"seg2\">WORKDIR</span> /app<br>\n<span class=\"dim\"># 비root 사용자 생성 후 전환</span><br>\n<span class=\"seg2\">RUN</span> useradd --system --no-create-home spring<br>\n<span class=\"seg2\">USER</span> spring<br>\n<span class=\"dim\"># build 스테이지에서 jar만 가져옴</span><br>\n<span class=\"seg2\">COPY</span> --from=build /app/build/libs/*.jar app.jar<br>\n<span class=\"seg2\">EXPOSE</span> 8080<br>\n<span class=\"seg2\">ENTRYPOINT</span> [<span class=\"seg\">\"java\"</span>, <span class=\"seg\">\"-jar\"</span>, <span class=\"seg\">\"/app/app.jar\"</span>]\n</div>\n<table>\n<tr><th>키워드</th><th>이 Dockerfile에서의 역할</th></tr>\n<tr><td><code>FROM ... AS build</code></td><td>빌드 전용 스테이지에 이름 부여. 런타임에서 <code>--from=build</code>로 참조</td></tr>\n<tr><td><code>COPY --from=build</code></td><td>build 스테이지의 산출물(jar)만 런타임 이미지로 복사 — Gradle·소스는 안 따라옴</td></tr>\n<tr><td><code>USER spring</code></td><td>이후 명령·컨테이너 프로세스를 비root로 실행. 권한 최소화</td></tr>\n<tr><td><code>ENTRYPOINT</code></td><td>컨테이너의 고정 실행 명령. <code>CMD</code>와 달리 인자로 잘 안 덮임 — 메인 프로세스에 적합</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">ENTRYPOINT vs CMD</span>\n<p><code>ENTRYPOINT</code>는 \"이 컨테이너는 무엇인가\"(여기선 자바 앱), <code>CMD</code>는 \"기본 인자\"입니다. exec 형식(<code>[\"java\",\"-jar\",...]</code>, 대괄호+JSON)을 쓰세요 — shell 형식(<code>java -jar ...</code>)은 PID 1이 셸이 되어 <code>SIGTERM</code>이 자바 프로세스에 전달되지 않아 graceful shutdown이 깨집니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 2 ============ -->\n<section id=\"docker-ch2\">\n<div class=\"ch-head\"><span class=\"ch-code\">DOCKER-02</span><h2>.dockerignore와 이미지 최적화</h2></div>\n<p class=\"lede\">언제·왜: <code>docker build</code>는 먼저 빌드 컨텍스트(현재 디렉터리 전체)를 데몬으로 전송합니다. <code>.gradle</code>·<code>build</code>·<code>node_modules</code>가 딸려가면 느리고, 캐시도 무의미하게 깨집니다. <em>컨텍스트를 줄이고, 잘 안 바뀌는 것부터 COPY</em>가 캐시의 핵심.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">.dockerignore — Dockerfile과 같은 위치</span>\n.git<br>\n.gradle<br>\nbuild<br>\n*.md<br>\n.env<br>\n.idea<br>\nnode_modules<br>\nDockerfile<br>\ncompose.yaml\n</div>\n<p>레이어 캐시는 <em>위에서부터 한 줄씩</em> 검증됩니다. 어떤 줄의 입력이 바뀌면 그 줄부터 아래 레이어가 전부 다시 빌드됩니다. 그래서 <strong>거의 안 바뀌는 의존성 정의를 먼저 COPY·다운로드하고, 자주 바뀌는 소스는 맨 나중에</strong> 복사합니다 (DOCKER-01의 순서가 그 이유). 소스만 고친 빌드에서 의존성 다운로드 단계가 캐시로 건너뛰어집니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">캐시 친화적 순서 (요지)</span>\n<span class=\"seg2\">COPY</span> build.gradle settings.gradle ./  <span class=\"dim\"># 1. 의존성 정의 (드물게 변경)</span><br>\n<span class=\"seg2\">RUN</span> gradle dependencies --no-daemon    <span class=\"dim\"># 2. 의존성 받기 → 캐시됨</span><br>\n<span class=\"seg2\">COPY</span> src ./src                          <span class=\"dim\"># 3. 소스 (자주 변경)</span><br>\n<span class=\"seg2\">RUN</span> gradle bootJar --no-daemon          <span class=\"dim\"># 4. 빌드</span>\n</div>\n<div class=\"callout\">\n<span class=\"co-label\">실전 팁</span>\n<p>이미지 크기를 더 줄이려면 런타임 베이스를 <code>eclipse-temurin:21-jre</code>처럼 <em>JRE</em> 변형으로(JDK 아님), 또는 <code>-alpine</code>/<code>-jammy</code> 슬림 태그로. 단 alpine은 glibc가 아니라 musl이라 일부 네이티브 라이브러리에서 문제가 날 수 있으니, 검증 없이 alpine으로 바꾸지 마세요.</p>\n</div>\n</section>\n\n<!-- ============ CH 3 ============ -->\n<section id=\"docker-ch3\">\n<div class=\"ch-head\"><span class=\"ch-code\">DOCKER-03</span><h2>compose — 이 스택 한 파일</h2></div>\n<p class=\"lede\">언제·왜: app(Spring Boot) + postgres + redis + nginx를 한 명령으로 띄우고 내립니다. 아래가 네 서비스를 다 담은 <code>compose.yaml</code> 골격 — 이후 챕터(환경변수·볼륨·네트워크·헬스체크)가 이 파일을 한 조각씩 채웁니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">compose.yaml — 전체 골격</span>\n<span class=\"seg2\">services:</span><br>\n&nbsp;&nbsp;<span class=\"seg\">app:</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;build: .<br>\n&nbsp;&nbsp;&nbsp;&nbsp;environment:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;SPRING_DATASOURCE_URL: jdbc:postgresql://postgres:5432/shop<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;SPRING_DATASOURCE_USERNAME: app_user<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;SPRING_DATASOURCE_PASSWORD: ${POSTGRES_PASSWORD}<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;SPRING_DATA_REDIS_HOST: redis<br>\n&nbsp;&nbsp;&nbsp;&nbsp;depends_on:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;postgres:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;condition: service_healthy<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;redis:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;condition: service_healthy<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg\">postgres:</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;image: postgres:16<br>\n&nbsp;&nbsp;&nbsp;&nbsp;environment:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;POSTGRES_DB: shop<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;POSTGRES_USER: app_user<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;POSTGRES_PASSWORD: ${POSTGRES_PASSWORD}<br>\n&nbsp;&nbsp;&nbsp;&nbsp;volumes:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;- pgdata:/var/lib/postgresql/data<br>\n&nbsp;&nbsp;&nbsp;&nbsp;healthcheck:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;test: [<span class=\"seg\">\"CMD-SHELL\"</span>, <span class=\"seg\">\"pg_isready -U app_user\"</span>]<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;interval: 10s<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;retries: 5<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg\">redis:</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;image: redis:7<br>\n&nbsp;&nbsp;&nbsp;&nbsp;command: redis-server --appendonly yes<br>\n&nbsp;&nbsp;&nbsp;&nbsp;volumes:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;- redisdata:/data<br>\n&nbsp;&nbsp;&nbsp;&nbsp;healthcheck:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;test: [<span class=\"seg\">\"CMD\"</span>, <span class=\"seg\">\"redis-cli\"</span>, <span class=\"seg\">\"ping\"</span>]<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;interval: 10s<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;retries: 5<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg\">nginx:</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;image: nginx:1.27<br>\n&nbsp;&nbsp;&nbsp;&nbsp;ports:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;- <span class=\"seg\">\"80:80\"</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;volumes:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;- ./nginx.conf:/etc/nginx/conf.d/default.conf:ro<br>\n&nbsp;&nbsp;&nbsp;&nbsp;depends_on:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;- app<br>\n<br>\n<span class=\"seg2\">volumes:</span><br>\n&nbsp;&nbsp;pgdata:<br>\n&nbsp;&nbsp;redisdata:\n</div>\n<div class=\"callout warn\">\n<span class=\"co-label\">포트 노출 범위</span>\n<p>외부로 여는 포트는 <code>nginx</code>의 <code>80:80</code> 하나뿐입니다. app·postgres·redis는 <code>ports</code>를 두지 않아 호스트로 노출되지 않고, compose 내부 네트워크에서만 서로 통신합니다(DOCKER-06). DB 포트를 호스트로 굳이 열지 마세요 — 로컬 디버깅이 꼭 필요할 때만 <code>\"5432:5432\"</code>를 한시적으로 추가하세요.</p>\n</div>\n</section>\n\n<!-- ============ CH 4 ============ -->\n<section id=\"docker-ch4\">\n<div class=\"ch-head\"><span class=\"ch-code\">DOCKER-04</span><h2>환경변수·설정 주입</h2></div>\n<p class=\"lede\">언제·왜: 같은 이미지를 환경(local·staging·prod)별로 다르게 띄우려면 설정을 코드가 아니라 <em>환경변수</em>로 주입해야 합니다. Spring Boot는 <code>SPRING_</code> 접두 환경변수를 properties로 자동 매핑합니다.</p>\n<table>\n<tr><th>환경변수</th><th>매핑되는 Spring 설정 / 용도</th></tr>\n<tr><td><code>SPRING_PROFILES_ACTIVE</code></td><td>활성 프로파일 (<code>local</code>/<code>prod</code>). <code>application-prod.yml</code> 선택</td></tr>\n<tr><td><code>SPRING_DATASOURCE_URL</code></td><td>JDBC URL — <code>jdbc:postgresql://postgres:5432/shop</code></td></tr>\n<tr><td><code>SPRING_DATASOURCE_USERNAME</code></td><td>DB 사용자</td></tr>\n<tr><td><code>SPRING_DATASOURCE_PASSWORD</code></td><td>DB 비밀번호 — <code>.env</code>·secret으로 주입</td></tr>\n<tr><td><code>SPRING_DATA_REDIS_HOST</code></td><td>Redis 호스트 — 서비스명 <code>redis</code></td></tr>\n</table>\n<p>compose는 같은 디렉터리의 <code>.env</code> 파일을 자동으로 읽어 <code>${VAR}</code> 치환에 씁니다. 비밀값은 yaml에 직접 박지 말고 <code>.env</code>로 분리하고, <code>.env</code>는 git에서 제외하세요(<code>.gitignore</code>·<code>.dockerignore</code> 둘 다).</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">.env — compose.yaml과 같은 위치 (git 제외)</span>\nPOSTGRES_PASSWORD=change-me-in-secret-manager<br>\nSPRING_PROFILES_ACTIVE=prod\n</div>\n<div class=\"serial-card\">\n<span class=\"sc-label\">app 서비스 — .env 값 참조 + 파일째 주입</span>\n&nbsp;&nbsp;<span class=\"seg\">app:</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;build: .<br>\n&nbsp;&nbsp;&nbsp;&nbsp;env_file:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;- .env<br>\n&nbsp;&nbsp;&nbsp;&nbsp;environment:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;SPRING_PROFILES_ACTIVE: ${SPRING_PROFILES_ACTIVE}<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;SPRING_DATASOURCE_PASSWORD: ${POSTGRES_PASSWORD}\n</div>\n<div class=\"callout risk\">\n<span class=\"co-label\">secret을 이미지에 굽지 마라</span>\n<p>비밀번호·토큰을 <code>Dockerfile</code>의 <code>ENV</code>나 빌드 인자로 넣으면 이미지 레이어에 영구히 남아 <code>docker history</code>로 노출됩니다. 비밀은 <em>런타임에</em> 환경변수·secret으로 주입하고, 운영에서는 <code>.env</code>가 아니라 secret manager를 쓰세요. <code>.env</code>는 반드시 <code>.dockerignore</code>·<code>.gitignore</code>에 둘 것.</p>\n</div>\n</section>\n\n<!-- ============ CH 5 ============ -->\n<section id=\"docker-ch5\">\n<div class=\"ch-head\"><span class=\"ch-code\">DOCKER-05</span><h2>데이터 영속 — 볼륨</h2></div>\n<p class=\"lede\">언제·왜: 컨테이너는 지워지면 안의 데이터도 사라집니다. DB 데이터가 컨테이너 수명과 함께 증발하면 안 되니, <em>named volume</em>에 데이터를 두어 컨테이너를 재생성해도 살아남게 합니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">postgres·redis 볼륨 매핑</span>\n&nbsp;&nbsp;<span class=\"seg\">postgres:</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;image: postgres:16<br>\n&nbsp;&nbsp;&nbsp;&nbsp;volumes:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;- pgdata:/var/lib/postgresql/data   <span class=\"dim\"># PG 데이터 디렉터리</span><br>\n<br>\n&nbsp;&nbsp;<span class=\"seg\">redis:</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;image: redis:7<br>\n&nbsp;&nbsp;&nbsp;&nbsp;command: redis-server --appendonly yes  <span class=\"dim\"># AOF 영속 켜기</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;volumes:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;- redisdata:/data                  <span class=\"dim\"># AOF/RDB 저장 위치</span><br>\n<br>\n<span class=\"dim\"># 파일 맨 아래 — named volume 선언</span><br>\n<span class=\"seg2\">volumes:</span><br>\n&nbsp;&nbsp;pgdata:<br>\n&nbsp;&nbsp;redisdata:\n</div>\n<table>\n<tr><th>구분</th><th>형태 / 설명</th></tr>\n<tr><td>named volume</td><td><code>pgdata:/var/lib/postgresql/data</code> — Docker가 관리. DB 데이터에 권장</td></tr>\n<tr><td>bind mount</td><td><code>./nginx.conf:/etc/...:ro</code> — 호스트 파일 직결. 설정 파일·소스에 적합. <code>:ro</code>는 읽기전용</td></tr>\n<tr><td>Redis AOF</td><td><code>--appendonly yes</code> — 모든 쓰기를 append-only 로그로 기록해 재기동 시 복원</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">데이터를 지우는 명령 구분</span>\n<p><code>docker compose down</code>은 컨테이너·네트워크만 지우고 named volume은 <em>남깁니다</em>. <code>docker compose down -v</code>는 볼륨까지 삭제 — DB 데이터가 통째로 날아갑니다. 캐시(redis)는 날려도 무방하지만, postgres 볼륨에 <code>-v</code>를 거는 건 운영에서 사고의 지름길입니다. 캐시 용도면 redis는 영속을 끄는 선택도 있습니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 6 ============ -->\n<section id=\"docker-ch6\">\n<div class=\"ch-head\"><span class=\"ch-code\">DOCKER-06</span><h2>서비스 간 네트워크</h2></div>\n<p class=\"lede\">언제·왜: compose는 프로젝트마다 기본 네트워크를 만들고, 모든 서비스를 거기에 붙입니다. 같은 네트워크 안에서는 <em>서비스명이 곧 호스트명</em>(내부 DNS)이라, <code>localhost</code>가 아니라 서비스명으로 서로를 찾습니다.</p>\n<table>\n<tr><th>출발 → 도착</th><th>연결 주소 (서비스명 = 호스트)</th></tr>\n<tr><td>app → postgres</td><td><code>jdbc:postgresql://postgres:5432/shop</code></td></tr>\n<tr><td>app → redis</td><td>host=<code>redis</code>, port=<code>6379</code></td></tr>\n<tr><td>nginx → app</td><td><code>proxy_pass http://app:8080;</code></td></tr>\n<tr><td>호스트(브라우저) → nginx</td><td><code>http://localhost</code> (nginx의 <code>80:80</code>만 외부 노출)</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">nginx.conf — app으로 리버스 프록시</span>\n<span class=\"seg2\">server</span> {<br>\n&nbsp;&nbsp;listen 80;<br>\n&nbsp;&nbsp;<span class=\"seg2\">location</span> / {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"dim\"># 서비스명 app = compose 내부 DNS</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;proxy_pass http://app:8080;<br>\n&nbsp;&nbsp;&nbsp;&nbsp;proxy_set_header Host $host;<br>\n&nbsp;&nbsp;&nbsp;&nbsp;proxy_set_header X-Real-IP $remote_addr;<br>\n&nbsp;&nbsp;}<br>\n}\n</div>\n<div class=\"callout warn\">\n<span class=\"co-label\">localhost 함정</span>\n<p>컨테이너 안에서 <code>localhost</code>는 <em>그 컨테이너 자신</em>이지 호스트나 다른 서비스가 아닙니다. app의 DB URL을 <code>jdbc:postgresql://localhost:5432</code>로 두면 app 컨테이너 안에서 자기 자신을 찾다가 실패합니다 — 반드시 서비스명 <code>postgres</code>를 쓰세요. 별도 <code>networks:</code> 선언 없이도 같은 compose 파일의 서비스끼리는 기본 네트워크로 자동 연결됩니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 7 ============ -->\n<section id=\"docker-ch7\">\n<div class=\"ch-head\"><span class=\"ch-code\">DOCKER-07</span><h2>헬스체크·기동 순서</h2></div>\n<p class=\"lede\">언제·왜: <code>depends_on</code>만으로는 \"postgres 컨테이너가 <em>시작</em>됐다\"까지만 보장하지, \"DB가 <em>접속 받을 준비</em>가 됐다\"는 보장하지 않습니다. app이 DB보다 먼저 붙어 죽는 경쟁을 막으려면 <code>healthcheck</code> + <code>condition: service_healthy</code>가 필요합니다.</p>\n<div class=\"flow\">\n<span class=\"step\">컨테이너 start</span><span class=\"arr\">→</span><span class=\"step\">healthcheck 통과</span><span class=\"arr\">→</span><span class=\"step hl\">service_healthy</span><span class=\"arr\">→</span><span class=\"step\">app 기동</span>\n</div>\n<div class=\"serial-card\">\n<span class=\"sc-label\">healthcheck + depends_on (조건부)</span>\n&nbsp;&nbsp;<span class=\"seg\">postgres:</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;image: postgres:16<br>\n&nbsp;&nbsp;&nbsp;&nbsp;healthcheck:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;test: [<span class=\"seg\">\"CMD-SHELL\"</span>, <span class=\"seg\">\"pg_isready -U app_user\"</span>]<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;interval: 10s    <span class=\"dim\"># 검사 주기</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;timeout: 5s      <span class=\"dim\"># 한 번 검사 제한시간</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;retries: 5       <span class=\"dim\"># 실패 N회면 unhealthy</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;start_period: 30s <span class=\"dim\"># 초기 유예 (실패로 안 셈)</span><br>\n<br>\n&nbsp;&nbsp;<span class=\"seg\">app:</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;build: .<br>\n&nbsp;&nbsp;&nbsp;&nbsp;depends_on:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;postgres:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;condition: service_healthy  <span class=\"dim\"># healthy 될 때까지 대기</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;redis:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;condition: service_healthy\n</div>\n<table>\n<tr><th>condition 값</th><th>의미</th></tr>\n<tr><td><code>service_started</code></td><td>컨테이너가 시작되기만 하면 (기본값, 약한 보장)</td></tr>\n<tr><td><code>service_healthy</code></td><td>healthcheck가 통과해 healthy 상태일 때까지 대기</td></tr>\n<tr><td><code>service_completed_successfully</code></td><td>해당 서비스가 정상 종료(exit 0)했을 때 — 마이그레이션 잡 등</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">실전 팁</span>\n<p>그래도 앱은 DB 연결 실패에 <em>재시도</em>로 대응하도록 짜는 게 안전합니다 — healthcheck는 경쟁을 줄여줄 뿐 모든 일시 장애를 막진 못합니다. <code>pg_isready</code>는 postgres 이미지에 기본 포함, <code>redis-cli ping</code>은 redis 이미지에 기본 포함이라 추가 설치가 필요 없습니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 8 ============ -->\n<section id=\"docker-ch8\">\n<div class=\"ch-head\"><span class=\"ch-code\">DOCKER-08</span><h2>자주 쓰는 명령</h2></div>\n<p class=\"lede\">언제·왜: 일상의 띄우기·내리기·로그·디버깅·정리. compose 명령과 단일 컨테이너 명령을 나눠 손에 붙입니다.</p>\n<table>\n<tr><th>compose 명령</th><th>의미 / 형태</th></tr>\n<tr><td><code>docker compose up -d</code></td><td>전체 스택을 백그라운드(<code>-d</code>)로 기동. <code>--build</code>로 이미지 재빌드 동반</td></tr>\n<tr><td><code>docker compose down</code></td><td>컨테이너·네트워크 정리(볼륨 유지). <code>-v</code>면 볼륨까지 삭제</td></tr>\n<tr><td><code>docker compose logs -f app</code></td><td>app 서비스 로그 실시간 추적(<code>-f</code>). 서비스명 빼면 전체</td></tr>\n<tr><td><code>docker compose ps</code></td><td>이 프로젝트 서비스 상태(포트·health) 확인</td></tr>\n<tr><td><code>docker compose exec app sh</code></td><td>실행 중인 app 컨테이너에 셸로 진입(디버깅)</td></tr>\n<tr><td><code>docker compose restart app</code></td><td>app만 재기동</td></tr>\n</table>\n<table>\n<tr><th>단일 컨테이너·이미지</th><th>의미 / 형태</th></tr>\n<tr><td><code>docker build -t shop-app .</code></td><td>현재 Dockerfile로 이미지 빌드 + 태그(<code>-t</code>)</td></tr>\n<tr><td><code>docker run --rm -p 8080:8080 shop-app</code></td><td>이미지를 단독 실행. <code>--rm</code> 종료 시 자동 삭제</td></tr>\n<tr><td><code>docker ps</code> / <code>docker ps -a</code></td><td>실행 중 / 멈춘 것 포함 전체 컨테이너</td></tr>\n<tr><td><code>docker images</code></td><td>로컬 이미지 목록·크기</td></tr>\n<tr><td><code>docker exec -it &lt;id&gt; sh</code></td><td>임의 컨테이너에 인터랙티브 셸 진입</td></tr>\n<tr><td><code>docker logs -f &lt;id&gt;</code></td><td>임의 컨테이너 로그 추적</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">정리(prune)는 무엇을 지우는지 보고</span>\n<p><code>docker system prune</code>은 멈춘 컨테이너·미사용 네트워크·dangling 이미지를 지웁니다. <code>-a</code>를 붙이면 <em>사용 중이 아닌 모든 이미지</em>까지, <code>--volumes</code>면 미사용 볼륨까지 삭제됩니다 — DB 볼륨이 미사용으로 잡혀 날아갈 수 있으니 운영 머신에서 <code>--volumes</code>는 신중히. 디스크가 부족할 때 <code>docker system df</code>로 먼저 무엇이 용량을 먹는지 확인하세요.</p>\n</div>\n</section>\n\n<!-- ============ CH 9 ============ -->\n<section id=\"docker-ch9\">\n<div class=\"ch-head\"><span class=\"ch-code\">DOCKER-09</span><h2>치트시트</h2></div>\n<p class=\"lede\">Dockerfile 키워드·compose 구조·자주 쓰는 명령을 한 곳에. 외우기보다 \"이런 게 있다\"를 알고 필요할 때 찾으세요.</p>\n<div class=\"glossary\">\n<div class=\"g-row\"><div class=\"g-term\"><b>FROM</b><span>base image</span></div><div class=\"g-def\">베이스 이미지 지정. <code>FROM img AS name</code>으로 멀티스테이지 스테이지 이름 부여</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>WORKDIR</b><span>작업 디렉터리</span></div><div class=\"g-def\">이후 명령의 기준 경로 설정·생성. <code>cd</code> 대신 이걸로</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>COPY</b><span>파일 복사</span></div><div class=\"g-def\">빌드 컨텍스트→이미지. <code>COPY --from=build /src dst</code>로 다른 스테이지에서 가져오기</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>RUN</b><span>빌드 시 실행</span></div><div class=\"g-def\">이미지 빌드 중 명령 실행(의존성 설치·빌드). 결과가 레이어로 남음</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>USER</b><span>실행 사용자</span></div><div class=\"g-def\">이후 명령·런타임 프로세스를 지정 사용자로. 비root 권장</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>ENTRYPOINT / CMD</b><span>실행 명령</span></div><div class=\"g-def\">ENTRYPOINT=고정 실행, CMD=기본 인자. exec 형식 <code>[\"java\",\"-jar\",..]</code> 권장</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>멀티스테이지</b><span>build → runtime</span></div><div class=\"g-def\">빌드 도구는 빌드 스테이지에만, 런타임 이미지엔 산출물만. 이미지 슬림화</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>services</b><span>compose 최상위</span></div><div class=\"g-def\">각 컨테이너를 정의. <code>build</code>(직접 빌드) 또는 <code>image</code>(공개 이미지)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>environment / env_file</b><span>설정 주입</span></div><div class=\"g-def\">환경변수 직접 지정 / <code>.env</code> 파일째 주입. <code>${VAR}</code> 치환은 <code>.env</code>에서</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>ports</b><span>호스트:컨테이너</span></div><div class=\"g-def\"><code>\"80:80\"</code> 호스트 포트를 컨테이너에 매핑. 안 쓰면 외부 비노출</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>volumes</b><span>데이터 영속</span></div><div class=\"g-def\">named volume(<code>pgdata:/path</code>) / bind mount(<code>./f:/path:ro</code>). 파일 하단에 named volume 선언</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>depends_on</b><span>기동 순서</span></div><div class=\"g-def\"><code>condition: service_healthy</code>로 healthcheck 통과까지 대기</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>healthcheck</b><span>준비 상태 검사</span></div><div class=\"g-def\"><code>test</code>·<code>interval</code>·<code>retries</code>·<code>start_period</code>. <code>pg_isready</code>, <code>redis-cli ping</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>서비스명 = DNS</b><span>내부 네트워크</span></div><div class=\"g-def\">같은 compose 안에서 <code>postgres</code>·<code>redis</code>·<code>app</code>이 곧 호스트명. localhost 아님</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>up -d / down</b><span>기동 / 정리</span></div><div class=\"g-def\"><code>docker compose up -d --build</code> 띄우기, <code>down</code> 내리기(<code>-v</code> 볼륨까지)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>logs -f / exec</b><span>로그 / 진입</span></div><div class=\"g-def\"><code>docker compose logs -f app</code> 추적, <code>docker compose exec app sh</code> 셸 진입</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>ps / images</b><span>상태 확인</span></div><div class=\"g-def\"><code>docker compose ps</code> 서비스 상태, <code>docker images</code> 이미지 목록·크기</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>system prune</b><span>정리</span></div><div class=\"g-def\"><code>docker system prune</code>(미사용 정리), <code>-a</code> 미사용 이미지까지, <code>--volumes</code> 신중히</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>.dockerignore</b><span>컨텍스트 축소</span></div><div class=\"g-def\"><code>.git</code>·<code>build</code>·<code>.env</code> 제외. 빌드 빨라지고 캐시 안정·secret 유출 방지</div></div>\n</div>\n<div class=\"callout gm\">\n<span class=\"co-label\">레시피 사용 순서</span>\n<p>처음 띄울 때 동선: ① <code>Dockerfile</code>·<code>.dockerignore</code> 작성(DOCKER-01·02) → ② <code>compose.yaml</code>에 네 서비스 골격(DOCKER-03) → ③ <code>.env</code>로 비밀·프로파일 분리(DOCKER-04) → ④ 볼륨·네트워크·헬스체크 채우기(DOCKER-05~07) → ⑤ <code>docker compose up -d --build</code>로 기동, <code>logs -f</code>로 확인(DOCKER-08). 개념·운영 배포는 Docker·배포 핸드북에서 이어 보세요.</p>\n</div>\n</section>\n\n<footer>\nDOCKER EXAMPLES · V1 · 2026-06<br>\nSTACK : SPRING BOOT · POSTGRES · REDIS · NGINX · COMPOSE<br>\nNOTE : 버전 태그·비밀값은 프로젝트에 맞춰 고정 · COMPANION : DOCKER·배포 핸드북\n</footer>\n\n<section id=\"doc-nginx\">\n<div class=\"ch-head\"><span class=\"ch-code\">SOURCE</span><h2>nginx 예시</h2></div>\n</section>\n\n<header class=\"hero\">\n  <div class=\"hero-serial\">\n    <span>DOC : NGINX-EXAMPLES-V1</span>\n    <span>STACK : REVERSE PROXY · TLS · LB</span>\n    <span>LANG : KO</span>\n  </div>\n  <h1>nginx<br>예시 사례</h1>\n  <p class=\"hero-sub\">Spring Boot 앞단의 리버스 프록시부터 TLS·로드밸런싱까지 — 바로 쓰는 nginx 설정 레시피. 프론트엔드 빌드를 서빙하고, API 요청을 백엔드로 넘기고, 인증서를 붙이는 일상 동선을 설정 블록째로 모았습니다.</p>\n  <div class=\"hero-meta\">NOTE : 설정은 Linux 기준 — 경로는 보통 /etc/nginx/. 컨테이너 환경에선 호스트명을 서비스명(app)으로<br>COMPILED : 2026-06</div>\n</header>\n\n<!-- ============ CH 1 ============ -->\n<section id=\"nginx-ch1\">\n<div class=\"ch-head\"><span class=\"ch-code\">NGINX-01</span><h2>리버스 프록시</h2></div>\n<p class=\"lede\">가장 기본 동선부터. 브라우저가 nginx(80/443)에 들어오면, nginx가 그 요청을 뒤에 있는 Spring Boot(8080)로 <em>대신 넘겨주고</em> 응답을 받아 전달합니다. 클라이언트는 백엔드 포트를 직접 알 필요가 없습니다 — 이게 reverse proxy입니다.</p>\n<p>프론트로 치면 Next.js의 <code>rewrites</code>나 dev server proxy와 같은 역할을, 인프라 레이어에서 nginx가 합니다. 핵심은 <code>proxy_pass</code> 한 줄과, <em>원래 요청 정보를 백엔드에 그대로 알려주는</em> 헤더 전달입니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">/etc/nginx/conf.d/app.conf — REVERSE PROXY</span>\n<span class=\"seg\">server</span> {<br>\n&nbsp;&nbsp;<span class=\"seg2\">listen</span> 80;<br>\n&nbsp;&nbsp;<span class=\"seg2\">server_name</span> api.example.com;<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg\">location</span> / {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">proxy_pass</span> http://app:8080;<br>\n<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"dim\"># 원래 요청 정보를 백엔드에 전달</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">proxy_set_header</span> Host $host;<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">proxy_set_header</span> X-Real-IP $remote_addr;<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">proxy_set_header</span> X-Forwarded-For $proxy_add_x_forwarded_for;<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">proxy_set_header</span> X-Forwarded-Proto $scheme;<br>\n&nbsp;&nbsp;}<br>\n}\n</div>\n<p>왜 헤더 전달이 필요한가. nginx가 요청을 중계하면, 백엔드 입장에서 <em>모든 요청이 nginx에서 온 것</em>처럼 보입니다 — 진짜 클라이언트 IP도, 원래 접속한 도메인도, http였는지 https였는지도 가려집니다. 그래서 명시적으로 넘겨줍니다.</p>\n<table>\n<tr><th>헤더</th><th>무엇을 알려주는가</th></tr>\n<tr><td><code>Host $host</code></td><td>클라이언트가 요청한 원래 도메인. 백엔드가 도메인별 분기·리다이렉트 URL 생성에 사용</td></tr>\n<tr><td><code>X-Real-IP $remote_addr</code></td><td>직접 접속한 클라이언트의 실제 IP (단일 값)</td></tr>\n<tr><td><code>X-Forwarded-For</code></td><td>프록시 체인 누적 IP 목록. <code>$proxy_add_x_forwarded_for</code>가 기존 값 뒤에 클라이언트 IP를 이어붙임</td></tr>\n<tr><td><code>X-Forwarded-Proto $scheme</code></td><td>원래 프로토콜(http/https). 백엔드가 https 여부를 판단하는 근거</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">SPRING BOOT — X-Forwarded 신뢰 설정</span>\n<p>헤더만 보내도 Spring Boot가 자동으로 믿지는 않습니다. <code>application.yml</code>에 <code>server.forward-headers-strategy: framework</code>(또는 <code>native</code>)를 켜야 <code>X-Forwarded-*</code>를 반영해 <code>request.getScheme()</code>·redirect URL이 https로 잡힙니다. 이게 없으면 https로 들어왔는데 백엔드가 http로 리다이렉트하는 mixed-content 버그가 납니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 2 ============ -->\n<section id=\"nginx-ch2\">\n<div class=\"ch-head\"><span class=\"ch-code\">NGINX-02</span><h2>정적 파일·SPA</h2></div>\n<p class=\"lede\">프론트 빌드 산출물(React/Next export, Vite <code>dist/</code>)을 서빙하는 패턴. nginx가 정적 파일을 직접 내보내는 건 백엔드를 거치는 것보다 압도적으로 빠릅니다 — 디스크에서 바로 읽어 보냅니다.</p>\n<p>핵심은 SPA의 <em>client-side routing</em> 처리입니다. <code>/dashboard</code> 같은 경로는 실제 파일이 아니라 JavaScript 라우터가 그릴 화면이라, 그 경로로 새로고침하면 서버엔 해당 파일이 없어 404가 납니다. <code>try_files</code>로 <em>없으면 <code>index.html</code>로 떨어뜨리는</em> fallback이 필요합니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">SPA — STATIC SERVE + FALLBACK</span>\n<span class=\"seg\">server</span> {<br>\n&nbsp;&nbsp;<span class=\"seg2\">listen</span> 80;<br>\n&nbsp;&nbsp;<span class=\"seg2\">server_name</span> app.example.com;<br>\n&nbsp;&nbsp;<span class=\"seg2\">root</span> /var/www/dist;<br>\n&nbsp;&nbsp;<span class=\"seg2\">index</span> index.html;<br>\n<br>\n&nbsp;&nbsp;<span class=\"dim\"># SPA: 실제 파일이 없으면 index.html로 fallback</span><br>\n&nbsp;&nbsp;<span class=\"seg\">location</span> / {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">try_files</span> $uri $uri/ /index.html;<br>\n&nbsp;&nbsp;}<br>\n<br>\n&nbsp;&nbsp;<span class=\"dim\"># API 요청만 백엔드로 분리</span><br>\n&nbsp;&nbsp;<span class=\"seg\">location</span> /api/ {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">proxy_pass</span> http://app:8080;<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">proxy_set_header</span> Host $host;<br>\n&nbsp;&nbsp;}<br>\n}\n</div>\n<p><code>try_files $uri $uri/ /index.html</code>는 왼쪽부터 순서대로 시도합니다 — ① 요청 경로에 해당하는 파일(<code>$uri</code>)이 있나 → ② 디렉터리(<code>$uri/</code>)인가 → ③ 둘 다 없으면 <code>/index.html</code>을 돌려줌. 그래서 <code>/main.js</code>는 파일로, <code>/dashboard</code>는 index.html로 가서 라우터가 이어받습니다.</p>\n<table>\n<tr><th>디렉티브</th><th>의미</th></tr>\n<tr><td><code>root /var/www/dist</code></td><td>문서 루트. 요청 경로가 root 뒤에 그대로 붙음 (<code>/main.js</code> → <code>/var/www/dist/main.js</code>)</td></tr>\n<tr><td><code>alias</code></td><td>location 경로를 다른 디렉터리로 치환. location 접두어를 떼고 매핑할 때 (<code>root</code>와 동작이 다름 — 아래 주의)</td></tr>\n<tr><td><code>index index.html</code></td><td>디렉터리 요청 시 기본으로 내보낼 파일</td></tr>\n<tr><td><code>try_files</code></td><td>나열한 경로를 순서대로 시도, 마지막은 fallback</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">ROOT vs ALIAS — 자주 헷갈리는 함정</span>\n<p><code>root</code>는 요청 경로 전체를 디렉터리에 이어붙이고, <code>alias</code>는 location 접두어를 <em>떼고</em> 이어붙입니다. <code>location /static/ { alias /var/www/assets/; }</code>면 <code>/static/a.js</code> → <code>/var/www/assets/a.js</code>. 같은 걸 <code>root</code>로 쓰면 <code>/static/</code>이 안 떨어져 경로가 어긋납니다. <code>alias</code> 경로는 끝에 <code>/</code>를 맞춰 쓰세요.</p>\n</div>\n</section>\n\n<!-- ============ CH 3 ============ -->\n<section id=\"nginx-ch3\">\n<div class=\"ch-head\"><span class=\"ch-code\">NGINX-03</span><h2>TLS / HTTPS</h2></div>\n<p class=\"lede\">인증서를 붙여 443에서 https를 받고, 80으로 들어온 평문 요청은 https로 영구 리다이렉트(301)합니다. TLS 종료(termination)를 nginx가 맡으면, 뒤의 Spring Boot는 평문 http만 다루면 돼서 단순해집니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">HTTP → HTTPS 리다이렉트 + TLS 종료</span>\n<span class=\"dim\"># 80: 평문은 무조건 https로 올림</span><br>\n<span class=\"seg\">server</span> {<br>\n&nbsp;&nbsp;<span class=\"seg2\">listen</span> 80;<br>\n&nbsp;&nbsp;<span class=\"seg2\">server_name</span> api.example.com;<br>\n&nbsp;&nbsp;<span class=\"seg2\">return</span> 301 https://$host$request_uri;<br>\n}<br>\n<br>\n<span class=\"dim\"># 443: 실제 서비스</span><br>\n<span class=\"seg\">server</span> {<br>\n&nbsp;&nbsp;<span class=\"seg2\">listen</span> 443 ssl;<br>\n&nbsp;&nbsp;<span class=\"seg2\">server_name</span> api.example.com;<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg2\">ssl_certificate</span> /etc/letsencrypt/live/api.example.com/fullchain.pem;<br>\n&nbsp;&nbsp;<span class=\"seg2\">ssl_certificate_key</span> /etc/letsencrypt/live/api.example.com/privkey.pem;<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg\">location</span> / {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">proxy_pass</span> http://app:8080;<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">proxy_set_header</span> Host $host;<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">proxy_set_header</span> X-Forwarded-Proto $scheme;<br>\n&nbsp;&nbsp;}<br>\n}\n</div>\n<p>80 server 블록은 <code>return 301</code> 한 줄로 끝납니다 — 평문으로 들어온 요청은 같은 경로의 https로 즉시 돌려보냅니다. <code>$request_uri</code>는 쿼리스트링까지 포함한 원래 경로라, 리다이렉트 후에도 목적지가 보존됩니다.</p>\n<table>\n<tr><th>디렉티브</th><th>의미</th></tr>\n<tr><td><code>listen 443 ssl</code></td><td>443에서 TLS로 수신. <code>ssl</code> 파라미터가 핸드셰이크를 켬</td></tr>\n<tr><td><code>ssl_certificate</code></td><td>인증서 체인 파일(<code>fullchain.pem</code> — 서버 인증서 + 중간 CA). 체인이 빠지면 일부 클라이언트에서 검증 실패</td></tr>\n<tr><td><code>ssl_certificate_key</code></td><td>개인키(<code>privkey.pem</code>). 권한을 좁게 두고 절대 외부 노출 금지</td></tr>\n<tr><td><code>return 301</code></td><td>영구 리다이렉트. 브라우저가 캐시함 (테스트 땐 302로 시작하는 게 안전)</td></tr>\n</table>\n<div class=\"callout risk\">\n<span class=\"co-label\">개인키는 secret이다</span>\n<p><code>ssl_certificate_key</code>가 가리키는 <code>privkey.pem</code>은 노출되면 인증서가 무력화됩니다 — git에 절대 커밋하지 말고, 파일 권한을 <code>600</code>(소유자만 읽기)으로 두세요. Let's Encrypt를 쓴다면 certbot이 갱신을 자동화하지만, 갱신 후 <code>nginx -s reload</code>가 걸려 있는지 확인해야 만료 사고를 막습니다(→ NGINX-07).</p>\n</div>\n</section>\n\n<!-- ============ CH 4 ============ -->\n<section id=\"nginx-ch4\">\n<div class=\"ch-head\"><span class=\"ch-code\">NGINX-04</span><h2>로드 밸런싱</h2></div>\n<p class=\"lede\">백엔드 인스턴스가 여럿일 때, nginx가 요청을 나눠 보냅니다. <code>upstream</code> 블록에 서버들을 묶어 이름을 주고, <code>proxy_pass</code>가 그 이름을 가리키게 합니다. 기본 분배 방식은 round-robin(순서대로 돌려가며)입니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">UPSTREAM — 여러 인스턴스 분배</span>\n<span class=\"seg\">upstream</span> backend {<br>\n&nbsp;&nbsp;<span class=\"dim\"># least_conn;  ← 연결 수가 가장 적은 서버로 (주석 해제 시)</span><br>\n&nbsp;&nbsp;<span class=\"seg2\">server</span> app1:8080;<br>\n&nbsp;&nbsp;<span class=\"seg2\">server</span> app2:8080;<br>\n&nbsp;&nbsp;<span class=\"seg2\">server</span> app3:8080 weight=2;<br>\n}<br>\n<br>\n<span class=\"seg\">server</span> {<br>\n&nbsp;&nbsp;<span class=\"seg2\">listen</span> 80;<br>\n&nbsp;&nbsp;<span class=\"seg\">location</span> / {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">proxy_pass</span> http://backend;<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">proxy_set_header</span> Host $host;<br>\n&nbsp;&nbsp;}<br>\n}\n</div>\n<p>기본은 round-robin — 들어오는 요청을 <code>app1 → app2 → app3 → app1...</code> 순서로 돌립니다. <code>weight=2</code>를 주면 그 서버가 2배 더 받습니다(사양이 다른 인스턴스에). 요청 처리 시간이 들쭉날쭉하면 <code>least_conn</code>이 더 고르게 분배됩니다 — 그 순간 연결이 가장 적은 서버로 보냅니다.</p>\n<table>\n<tr><th>방식 / 옵션</th><th>의미</th></tr>\n<tr><td>round-robin (기본)</td><td>순서대로 균등 분배. 별도 지시어 없이 기본 동작</td></tr>\n<tr><td><code>least_conn</code></td><td>활성 연결이 가장 적은 서버로. 처리 시간 편차가 클 때 유리</td></tr>\n<tr><td><code>weight=N</code></td><td>server에 가중치. 사양 다른 인스턴스 간 비율 조정</td></tr>\n<tr><td><code>server app:8080 down</code></td><td>해당 서버를 일시적으로 분배 대상에서 제외 (점검 시)</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">SESSION — 무상태가 전제다</span>\n<p>round-robin은 매 요청을 다른 인스턴스로 보낼 수 있습니다. 세션을 서버 메모리에 들고 있으면 \"방금 로그인했는데 다음 요청에서 풀리는\" 문제가 납니다. 해법은 두 가지 — ① 세션을 Redis 같은 공유 저장소로 빼서 인스턴스를 무상태로(권장) ② <code>ip_hash</code>로 같은 IP를 같은 서버에 고정(sticky). 가능하면 ①로 가세요.</p>\n</div>\n</section>\n\n<!-- ============ CH 5 ============ -->\n<section id=\"nginx-ch5\">\n<div class=\"ch-head\"><span class=\"ch-code\">NGINX-05</span><h2>gzip·캐싱</h2></div>\n<p class=\"lede\">전송량을 줄이고, 안 바뀌는 자원은 브라우저가 다시 안 받게 합니다. 프론트 번들·CSS·JSON 응답을 gzip으로 압축하면 전송 크기가 크게 줄고, 해시가 박힌 정적 자원엔 긴 <code>expires</code>를 걸어 캐시합니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">GZIP + 정적 자원 캐시</span>\n<span class=\"dim\"># 응답 압축</span><br>\n<span class=\"seg2\">gzip</span> on;<br>\n<span class=\"seg2\">gzip_types</span> text/css application/javascript application/json image/svg+xml;<br>\n<span class=\"seg2\">gzip_min_length</span> 1024;<br>\n<br>\n<span class=\"seg\">server</span> {<br>\n&nbsp;&nbsp;<span class=\"seg2\">listen</span> 80;<br>\n&nbsp;&nbsp;<span class=\"seg2\">root</span> /var/www/dist;<br>\n<br>\n&nbsp;&nbsp;<span class=\"dim\"># 해시가 박힌 빌드 자원: 1년 캐시 + immutable</span><br>\n&nbsp;&nbsp;<span class=\"seg\">location</span> /assets/ {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">expires</span> 1y;<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">add_header</span> Cache-Control \"public, immutable\";<br>\n&nbsp;&nbsp;}<br>\n<br>\n&nbsp;&nbsp;<span class=\"dim\"># index.html은 캐시 금지 — 항상 최신 자원 해시를 받게</span><br>\n&nbsp;&nbsp;<span class=\"seg\">location</span> = /index.html {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">add_header</span> Cache-Control \"no-cache\";<br>\n&nbsp;&nbsp;}<br>\n}\n</div>\n<p>핵심 전략은 <em>\"자원은 길게 캐시, 진입점은 캐시 금지\"</em>입니다. Vite/webpack은 빌드 시 파일명에 콘텐츠 해시를 박습니다(<code>main.4f8a.js</code>) — 내용이 바뀌면 이름이 바뀌므로, 이름이 같으면 영원히 캐시해도 안전합니다(<code>immutable</code>). 반면 <code>index.html</code>은 캐시하면 옛 자원을 가리키게 되니 <code>no-cache</code>로 둡니다.</p>\n<table>\n<tr><th>디렉티브</th><th>의미</th></tr>\n<tr><td><code>gzip on</code></td><td>응답 압축 켜기</td></tr>\n<tr><td><code>gzip_types</code></td><td>압축할 MIME 타입. <code>text/html</code>은 기본 포함이라 생략. 이미 압축된 jpg/png는 제외</td></tr>\n<tr><td><code>expires 1y</code></td><td><code>Expires</code>·<code>Cache-Control: max-age</code> 헤더를 자동 설정</td></tr>\n<tr><td><code>add_header Cache-Control</code></td><td>캐시 정책 직접 지정. <code>immutable</code>은 재검증도 생략</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">PROXY_CACHE — 백엔드 응답도 캐시</span>\n<p>정적 파일뿐 아니라 백엔드 응답도 캐시할 수 있습니다. <code>http</code> 컨텍스트에 <code>proxy_cache_path /var/cache/nginx levels=1:2 keys_zone=api:10m;</code>로 캐시 영역을 만들고, location에 <code>proxy_cache api;</code> + <code>proxy_cache_valid 200 1m;</code>를 더하면 동일 요청을 1분간 nginx가 직접 응답합니다. 단, 잘 안 바뀌는 GET에만 — 인증·개인화 응답엔 쓰지 마세요.</p>\n</div>\n</section>\n\n<!-- ============ CH 6 ============ -->\n<section id=\"nginx-ch6\">\n<div class=\"ch-head\"><span class=\"ch-code\">NGINX-06</span><h2>보안 헤더·rate limit</h2></div>\n<p class=\"lede\">기본 보안 헤더 몇 개를 nginx 레벨에서 일괄로 붙이고, 무차별 요청(brute-force·스크래핑)을 속도 제한으로 막습니다. 애플리케이션 코드를 건드리지 않고 엣지에서 처리하는 게 장점입니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">보안 헤더 + RATE LIMIT</span>\n<span class=\"dim\"># http 컨텍스트: 분당 비율 제한 영역 정의</span><br>\n<span class=\"seg2\">limit_req_zone</span> $binary_remote_addr zone=api:10m rate=10r/s;<br>\n<br>\n<span class=\"seg\">server</span> {<br>\n&nbsp;&nbsp;<span class=\"seg2\">listen</span> 443 ssl;<br>\n<br>\n&nbsp;&nbsp;<span class=\"dim\"># 응답마다 보안 헤더 부착</span><br>\n&nbsp;&nbsp;<span class=\"seg2\">add_header</span> X-Frame-Options \"SAMEORIGIN\" always;<br>\n&nbsp;&nbsp;<span class=\"seg2\">add_header</span> X-Content-Type-Options \"nosniff\" always;<br>\n&nbsp;&nbsp;<span class=\"seg2\">add_header</span> Referrer-Policy \"strict-origin-when-cross-origin\" always;<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg\">location</span> /api/login {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"dim\"># 순간 폭주는 burst로 흡수, 초과는 거절</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">limit_req</span> zone=api burst=20 nodelay;<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg2\">proxy_pass</span> http://app:8080;<br>\n&nbsp;&nbsp;}<br>\n}\n</div>\n<p>rate limit은 두 단계로 동작합니다. <code>limit_req_zone</code>이 <em>키(여기선 클라이언트 IP)·메모리 영역·기준 속도</em>를 정의하고, <code>limit_req</code>가 특정 location에 그 규칙을 적용합니다. <code>rate=10r/s</code>는 초당 10건, <code>burst=20</code>은 일시적으로 20건까지 큐에 담아 허용, <code>nodelay</code>는 그 burst를 지연 없이 즉시 처리하라는 뜻입니다.</p>\n<table>\n<tr><th>헤더 / 옵션</th><th>막는 것</th></tr>\n<tr><td><code>X-Frame-Options SAMEORIGIN</code></td><td>외부 사이트가 iframe으로 우리 페이지를 감싸는 clickjacking</td></tr>\n<tr><td><code>X-Content-Type-Options nosniff</code></td><td>브라우저의 MIME 추측 — 응답을 선언된 타입으로만 해석하게 강제</td></tr>\n<tr><td><code>always</code> (add_header)</td><td>4xx/5xx 에러 응답에도 헤더를 붙임 (없으면 일부 상태코드에서 누락)</td></tr>\n<tr><td><code>burst=N nodelay</code></td><td>순간 몰림 N건까지 흡수하되 지연 없이 처리. 초과분은 503</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">ADD_HEADER 상속 함정</span>\n<p><code>add_header</code>는 상속이 아니라 <em>덮어쓰기</em>입니다 — 하위 <code>location</code>에서 <code>add_header</code>를 하나라도 쓰면, 상위 <code>server</code>에 선언한 보안 헤더들이 그 location에서 <em>전부 사라집니다</em>. 그래서 location마다 다시 선언하거나, 공통 헤더를 별도 파일로 빼서 <code>include</code>하는 패턴을 씁니다. \"왜 이 경로만 헤더가 없지?\"의 단골 원인입니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 7 ============ -->\n<section id=\"nginx-ch7\">\n<div class=\"ch-head\"><span class=\"ch-code\">NGINX-07</span><h2>운영 — 검증·리로드</h2></div>\n<p class=\"lede\">설정을 바꿨으면 <em>적용 전에 문법을 검사</em>하고, 무중단으로 반영합니다. nginx는 설정 오류가 있으면 리로드를 거부하므로, <code>nginx -t</code>를 먼저 거는 습관이 서비스 다운을 막습니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">검증 → 무중단 리로드</span>\n<span class=\"dim\"># 1. 문법·설정 검사 (실제 적용 안 함)</span><br>\n$ nginx <span class=\"seg\">-t</span><br>\n<span class=\"dim\">nginx: configuration file /etc/nginx/nginx.conf test is successful</span><br>\n<br>\n<span class=\"dim\"># 2. 무중단 리로드 (기존 연결 유지하며 새 설정 적용)</span><br>\n$ nginx <span class=\"seg\">-s reload</span><br>\n<br>\n<span class=\"dim\"># 검사 + 리로드를 한 줄로 (검사 실패 시 리로드 안 함)</span><br>\n$ nginx -t <span class=\"dim\">&amp;&amp;</span> nginx -s reload\n</div>\n<p><code>nginx -s reload</code>는 재시작이 아닙니다 — master 프로세스가 새 설정으로 새 worker를 띄우고, 기존 worker는 진행 중인 요청을 다 끝낸 뒤 종료합니다. 그래서 사용자 연결이 끊기지 않습니다. <code>&amp;&amp;</code>로 묶으면 <code>nginx -t</code>가 성공할 때만 리로드가 실행돼, 깨진 설정이 반영되는 사고를 원천 차단합니다.</p>\n<table>\n<tr><th>명령 / 위치</th><th>역할</th></tr>\n<tr><td><code>nginx -t</code></td><td>설정 문법 검사. 적용은 안 함 — 항상 reload 전에</td></tr>\n<tr><td><code>nginx -s reload</code></td><td>무중단 설정 재적용 (graceful)</td></tr>\n<tr><td><code>nginx -s quit</code></td><td>진행 중 요청 끝내고 graceful 종료 (<code>stop</code>은 즉시)</td></tr>\n<tr><td><code>/var/log/nginx/access.log</code></td><td>접속 로그. 상태코드·응답시간 추적</td></tr>\n<tr><td><code>/var/log/nginx/error.log</code></td><td>에러 로그. 502/504·설정 문제는 여기부터 보기</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">502 / 504 — 어디서 끊겼나</span>\n<p>리버스 프록시에서 가장 흔한 두 에러. <strong>502 Bad Gateway</strong>는 백엔드에 연결은 시도했지만 거부·죽음(보통 Spring Boot가 안 떠 있거나 <code>proxy_pass</code> 주소가 틀림). <strong>504 Gateway Timeout</strong>은 백엔드가 응답을 제때 못 줌(처리 지연). <code>error.log</code>에 어느 upstream으로 갔다 실패했는지 찍히니, 추적은 항상 거기서 시작하세요(→ Linux 핸드북 LX-03 <code>tail -f</code>).</p>\n</div>\n</section>\n\n<!-- ============ CH 8 ============ -->\n<section id=\"nginx-ch8\">\n<div class=\"ch-head\"><span class=\"ch-code\">NGINX-08</span><h2>치트시트 — 디렉티브 한눈에</h2></div>\n<p class=\"lede\">앞에서 다룬 핵심 디렉티브를 한 곳에. 외우기보다 \"이걸 쓰면 된다\"를 떠올리고 본문 섹션에서 전체 블록을 찾으세요.</p>\n<div class=\"glossary\">\n<div class=\"g-row\"><div class=\"g-term\"><b>리버스 프록시</b><span>reverse proxy</span></div><div class=\"g-def\">앞단 nginx가 받은 요청을 뒤의 백엔드로 중계. 클라이언트는 백엔드 포트를 모름 (→ NGINX-01)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>proxy_pass</b><span>upstream으로 전달</span></div><div class=\"g-def\"><code>proxy_pass http://app:8080;</code> — location에 들어온 요청을 지정 주소로 넘김</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>proxy_set_header</b><span>원요청 정보 전달</span></div><div class=\"g-def\"><code>Host</code> · <code>X-Real-IP</code> · <code>X-Forwarded-For</code> · <code>X-Forwarded-Proto</code> — 가려진 클라이언트 정보를 백엔드에 알림</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>try_files</b><span>SPA fallback</span></div><div class=\"g-def\"><code>try_files $uri $uri/ /index.html;</code> — 파일 없으면 index.html로 떨어뜨려 client routing 보존 (→ NGINX-02)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>root / alias</b><span>문서 경로 매핑</span></div><div class=\"g-def\"><code>root</code>는 요청 경로를 이어붙이고, <code>alias</code>는 location 접두어를 떼고 매핑</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>listen 443 ssl</b><span>HTTPS 수신</span></div><div class=\"g-def\"><code>ssl_certificate</code>(fullchain) + <code>ssl_certificate_key</code>(privkey) 짝. 80은 <code>return 301</code>로 리다이렉트 (→ NGINX-03)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>upstream</b><span>로드 밸런싱 풀</span></div><div class=\"g-def\"><code>upstream backend { server app1; server app2; }</code> — 기본 round-robin, <code>least_conn</code>·<code>weight</code> 조절 (→ NGINX-04)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>gzip</b><span>응답 압축</span></div><div class=\"g-def\"><code>gzip on;</code> + <code>gzip_types</code>로 css/js/json 압축. 전송량 감소</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>expires / Cache-Control</b><span>정적 캐시</span></div><div class=\"g-def\">해시 박힌 자원 <code>expires 1y; add_header Cache-Control \"public, immutable\";</code>, index.html은 <code>no-cache</code> (→ NGINX-05)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>add_header (보안)</b><span>X-Frame / nosniff</span></div><div class=\"g-def\"><code>X-Frame-Options</code> · <code>X-Content-Type-Options</code>. 끝에 <code>always</code>, 하위 location에서 덮어써지는 상속 함정 주의 (→ NGINX-06)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>limit_req</b><span>속도 제한</span></div><div class=\"g-def\"><code>limit_req_zone ... rate=10r/s;</code>로 정의 → location에 <code>limit_req zone=api burst=20 nodelay;</code>로 적용</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>nginx -t</b><span>설정 검사</span></div><div class=\"g-def\">적용 전 문법 검사. 항상 reload 전에 거는 안전장치</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>nginx -s reload</b><span>무중단 리로드</span></div><div class=\"g-def\">기존 연결 유지하며 새 설정 적용. <code>nginx -t &amp;&amp; nginx -s reload</code> 한 줄 패턴 (→ NGINX-07)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>error.log</b><span>장애 추적 시작점</span></div><div class=\"g-def\"><code>/var/log/nginx/error.log</code> — 502(백엔드 다운)·504(타임아웃)는 여기서</div></div>\n</div>\n<div class=\"callout gm\">\n<span class=\"co-label\">학습 순서 제안</span>\n<p>전부 한 번에 잡지 마세요. 프론트 출신이라면 손에 먼저 붙일 것: <code>proxy_pass</code> + <code>proxy_set_header</code>(NGINX-01)와 <code>try_files</code> SPA fallback(NGINX-02). 이 둘이 \"프론트 빌드 서빙 + API 프록시\"라는 가장 흔한 배포 형태를 커버합니다. 그다음 TLS(NGINX-03) → 운영 검증(NGINX-07) 순으로. 로드 밸런싱·rate limit은 트래픽이 커질 때 본문에서 찾으면 됩니다(→ Linux 핸드북·백엔드 핸드북과 함께 보면 배포 동선이 이어집니다).</p>\n</div>\n</section>\n\n<footer>\nNGINX EXAMPLES · V1 · 2026-06<br>\nSTACK : REVERSE PROXY · TLS · LOAD BALANCING · BEFORE SPRING BOOT<br>\nNOTE : 경로·인증서는 환경에 맞게 · 설정 변경 후 항상 nginx -t · COMPANION : LINUX HANDBOOK · BACKEND HANDBOOK\n</footer>",
};

export default document;
